import { useState, useEffect } from "react";
import { ActivityService } from "../../services/ActivityService";
import type { Activity } from "../../services/ActivityService";
import { useTranslation } from "react-i18next";
import { X, Upload, Save, Loader2, Plus, Trash2 } from "lucide-react";
import { motion } from "framer-motion";

interface ActivityEditorModalProps {
  isOpen: boolean;
  onClose: () => void;
  activity?: Activity | null;
  onSaved: () => void;
}

const DEFAULT_ACTIVITY: Partial<Activity> = {
  title: "",
  category: "educational",
  description: "",
  price: 0,
  price_member: 0,
  price_non_member: 0,
  price_info: "/mes",
  grades: "",
  schedule_summary: "",
  place: "",
  spots: 10,
  image_url: "",
  color: "bg-blue-500",
  category_icon: "school",
  is_stem_approved: false,
  schedule_details: [],
  important_note: ""
};

export function ActivityEditorModal({ isOpen, onClose, activity, onSaved }: ActivityEditorModalProps) {
  const { t } = useTranslation();
  const [formData, setFormData] = useState<Partial<Activity>>(DEFAULT_ACTIVITY);
  const [loading, setLoading] = useState(false);
  const [imageFile, setImageFile] = useState<File | null>(null);
  const [imagePreview, setImagePreview] = useState<string>("");
  const [currentLang, setCurrentLang] = useState<'es' | 'ca' | 'en'>('es');

  useEffect(() => {
    if (activity) {
      setFormData(activity);
      setImagePreview(activity.image_url);
    } else {
      setFormData(DEFAULT_ACTIVITY);
      setImagePreview("");
    }
  }, [activity, isOpen]);

  const handleImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setImageFile(file);
      setImagePreview(URL.createObjectURL(file));
    }
  };

  const handleChange = <K extends keyof Activity>(field: K, value: Activity[K]) => {
    // If it's a translatable field, update the specific language field
    const translatableFields = ['title', 'description', 'grades', 'schedule_summary', 'important_note'];

    if (translatableFields.includes(field)) {
      const langKey = `${field}_${currentLang}` as keyof Activity;
      setFormData(prev => ({
        ...prev,
        [langKey]: value,
        // If editing Spanish, also update the legacy field for backward compatibility
        ...(currentLang === 'es' ? { [field]: value } : {})
      }));
    } else {
      setFormData(prev => ({ ...prev, [field]: value }));
    }
  };

  const getValue = (field: keyof Activity): string => {
    const langKey = `${field}_${currentLang}` as keyof Activity;
    const val = formData[langKey as keyof typeof formData];
    if (val !== undefined && val !== null) return String(val);

    return currentLang === 'es' && formData[field] ? String(formData[field]) : '';
  };

  // Schedule Details Handler
  const addScheduleGroup = () => {
    const current = formData.schedule_details || [];
    setFormData(prev => ({
      ...prev,
      schedule_details: [...current, { group: "Nou Grup", sessions: [] }]
    }));
  };

  const updateGroupName = (index: number, name: string) => {
    const current = [...(formData.schedule_details || [])];
    current[index] = { ...current[index], group: name };
    setFormData(prev => ({ ...prev, schedule_details: current }));
  };

  const removeScheduleGroup = (index: number) => {
    const current = [...(formData.schedule_details || [])];
    current.splice(index, 1);
    setFormData(prev => ({ ...prev, schedule_details: current }));
  };

  const addSession = (groupIndex: number) => {
    const current = [...(formData.schedule_details || [])];
    current[groupIndex].sessions = [
      ...current[groupIndex].sessions,
      { day: 1, startTime: "17:00", endTime: "18:30" }
    ];
    setFormData(prev => ({ ...prev, schedule_details: current }));
  };

  const updateSession = (groupIndex: number, sessionIndex: number, field: 'day' | 'startTime' | 'endTime', value: string | number) => {
    const current = [...(formData.schedule_details || [])];
    const session = { ...current[groupIndex].sessions[sessionIndex] };

    if (field === 'day') {
      session.day = typeof value === 'string' ? parseInt(value) : value;
    } else {
      session[field] = String(value);
    }

    current[groupIndex].sessions[sessionIndex] = session;
    setFormData(prev => ({ ...prev, schedule_details: current }));
  };

  const removeSession = (groupIndex: number, sessionIndex: number) => {
    const current = [...(formData.schedule_details || [])];
    current[groupIndex].sessions.splice(sessionIndex, 1);
    setFormData(prev => ({ ...prev, schedule_details: current }));
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    try {
      let url = formData.image_url;
      if (imageFile) {
        url = await ActivityService.uploadImage(imageFile);
      }

      const payload = { ...formData, image_url: url } as Omit<Activity, 'id' | 'created_at'>;

      if (activity?.id) {
        await ActivityService.update(activity.id, payload);
      } else {
        await ActivityService.create(payload);
      }
      onSaved();
      onClose();
    } catch (error) {
      console.error("Failed to save activity", error);
      alert(t('common.error_save'));
    } finally {
      setLoading(false);
    }
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm p-4">
      <motion.div
        initial={{ opacity: 0, scale: 0.95 }}
        animate={{ opacity: 1, scale: 1 }}
        exit={{ opacity: 0, scale: 0.95 }}
        className="bg-white dark:bg-slate-900 w-full max-w-4xl max-h-[90vh] rounded-2xl shadow-2xl flex flex-col overflow-hidden"
      >
        {/* Header */}
        <div className="flex justify-between items-center p-6 border-b border-slate-200 dark:border-slate-700">
          <h2 className="text-2xl font-bold dark:text-white">
            {activity ? t('admin.editor.edit_title') : t('admin.editor.new_title')}
          </h2>
          <button onClick={onClose} className="p-2 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-full transition-colors">
            <X className="w-6 h-6 text-slate-500" />
          </button>
        </div>

        {/* Content */}
        <div className="flex-1 overflow-y-auto p-6">
          {/* Language Tabs */}
          <div className="flex gap-2 mb-6 border-b border-slate-200 dark:border-slate-700 pb-1">
            <button
              type="button"
              onClick={() => setCurrentLang('es')}
              className={`px-4 py-2 text-sm font-bold rounded-t-lg transition-colors ${currentLang === 'es' ? 'bg-blue-50 dark:bg-blue-900/30 text-blue-600 dark:text-blue-400 border-b-2 border-blue-600' : 'text-slate-500 hover:text-slate-700'}`}
            >
              🇪🇸 Español
            </button>
            <button
              type="button"
              onClick={() => setCurrentLang('ca')}
              className={`px-4 py-2 text-sm font-bold rounded-t-lg transition-colors ${currentLang === 'ca' ? 'bg-blue-50 dark:bg-blue-900/30 text-blue-600 dark:text-blue-400 border-b-2 border-blue-600' : 'text-slate-500 hover:text-slate-700'}`}
            >
              🏴 Català
            </button>
            <button
              type="button"
              onClick={() => setCurrentLang('en')}
              className={`px-4 py-2 text-sm font-bold rounded-t-lg transition-colors ${currentLang === 'en' ? 'bg-blue-50 dark:bg-blue-900/30 text-blue-600 dark:text-blue-400 border-b-2 border-blue-600' : 'text-slate-500 hover:text-slate-700'}`}
            >
              🇬🇧 English
            </button>
          </div>

          <form id="activity-form" onSubmit={handleSubmit} className="space-y-6">

            {/* Main Info */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="space-y-2">
                <label className="text-sm font-medium text-slate-700 dark:text-slate-300">{t('admin.editor.title')} ({currentLang.toUpperCase()})</label>
                <input
                  required={currentLang === 'es'}
                  className="w-full px-4 py-2 rounded-lg border border-slate-300 dark:border-slate-600 dark:bg-slate-800 dark:text-white focus:ring-2 focus:ring-blue-500"
                  value={getValue('title')}
                  onChange={e => handleChange('title', e.target.value)}
                  placeholder={currentLang !== 'es' ? '(Optional) Leave empty to use default' : ''}
                />
              </div>
              <div className="space-y-2">
                <label className="text-sm font-medium text-slate-700 dark:text-slate-300">{t('admin.editor.category')}</label>
                <select
                  className="w-full px-4 py-2 rounded-lg border border-slate-300 dark:border-slate-600 dark:bg-slate-800 dark:text-white focus:ring-2 focus:ring-blue-500"
                  value={formData.category} // Category is universal
                  onChange={e => handleChange('category', e.target.value)}
                >
                  <option value="educational">{t('admin.editor.categories.educational')}</option>
                  <option value="artistic">{t('admin.editor.categories.artistic')}</option>
                  <option value="languages">{t('admin.editor.categories.languages')}</option>
                  <option value="music">{t('admin.editor.categories.music')}</option>
                  <option value="sports">{t('admin.editor.categories.sports')}</option>
                </select>
              </div>
            </div>

            {/* Description */}
            <div className="space-y-2">
              <label className="text-sm font-medium text-slate-700 dark:text-slate-300">{t('admin.editor.description')} ({currentLang.toUpperCase()})</label>
              <textarea
                rows={3}
                className="w-full px-4 py-2 rounded-lg border border-slate-300 dark:border-slate-600 dark:bg-slate-800 dark:text-white focus:ring-2 focus:ring-blue-500"
                value={getValue('description')}
                onChange={e => handleChange('description', e.target.value)}
              />
            </div>

            {/* Pricing & Logistics */}
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
              <div className="space-y-2">
                <label className="text-sm font-medium text-slate-700 dark:text-slate-300">{t('admin.editor.price_member' as any)}</label>
                <input
                  type="number"
                  className="w-full px-4 py-2 rounded-lg border border-slate-300 dark:border-slate-600 dark:bg-slate-800 dark:text-white focus:ring-2 focus:ring-blue-500"
                  value={formData.price_member ?? 0}
                  onChange={e => handleChange('price_member', parseFloat(e.target.value))}
                />
              </div>
              <div className="space-y-2">
                <label className="text-sm font-medium text-slate-700 dark:text-slate-300">{t('admin.editor.price_non_member' as any)}</label>
                <input
                  type="number"
                  className="w-full px-4 py-2 rounded-lg border border-slate-300 dark:border-slate-600 dark:bg-slate-800 dark:text-white focus:ring-2 focus:ring-blue-500"
                  value={formData.price_non_member ?? 0}
                  onChange={e => handleChange('price_non_member', parseFloat(e.target.value))}
                />
              </div>
              <div className="space-y-2">
                <label className="text-sm font-medium text-slate-700 dark:text-slate-300">{t('admin.editor.price_unit')}</label>
                <input
                  className="w-full px-4 py-2 rounded-lg border border-slate-300 dark:border-slate-600 dark:bg-slate-800 dark:text-white focus:ring-2 focus:ring-blue-500"
                  value={formData.price_info ?? ''}
                  onChange={e => handleChange('price_info', e.target.value)}
                />
              </div>
              <div className="space-y-2">
                <label className="text-sm font-medium text-slate-700 dark:text-slate-300">{t('admin.editor.spots')}</label>
                <input
                  type="number"
                  className="w-full px-4 py-2 rounded-lg border border-slate-300 dark:border-slate-600 dark:bg-slate-800 dark:text-white focus:ring-2 focus:ring-blue-500"
                  value={formData.spots ?? 0}
                  onChange={e => handleChange('spots', parseInt(e.target.value))}
                />
              </div>
            </div>

            {/* Image Upload */}
            <div className="space-y-2">
              <label className="text-sm font-medium text-slate-700 dark:text-slate-300">{t('admin.editor.image')}</label>
              <div className="flex gap-4 items-start">
                <div className="w-32 h-20 bg-slate-100 rounded-lg overflow-hidden border border-slate-300 flex items-center justify-center">
                  {imagePreview ? (
                    <img src={imagePreview} alt="Preview" className="w-full h-full object-cover" />
                  ) : (
                    <span className="text-xs text-slate-400">No Image</span>
                  )}
                </div>
                <div className="flex-1">
                  <label className="cursor-pointer inline-flex items-center gap-2 px-4 py-2 bg-slate-200 hover:bg-slate-300 text-slate-700 rounded-lg transition-colors text-sm font-medium">
                    <Upload className="w-4 h-4" /> {t('admin.editor.upload_image')}
                    <input type="file" className="hidden" accept="image/*" onChange={handleImageChange} />
                  </label>
                  <p className="text-xs text-slate-500 mt-2">{t('admin.editor.image_hint')}</p>
                </div>
              </div>
            </div>

            {/* Schedule Details (Structured Session Editor) */}
            <div className="space-y-4 bg-slate-50 dark:bg-slate-800/50 p-6 rounded-xl border border-slate-200 dark:border-slate-700">
              <div className="flex justify-between items-center mb-2">
                <div>
                  <h3 className="font-bold text-slate-900 dark:text-white">{t('admin.editor.schedule_title')}</h3>
                  <p className="text-xs text-slate-500">{t('admin.editor.schedule_subtitle')}</p>
                </div>
                <button type="button" onClick={addScheduleGroup} className="flex items-center gap-2 px-3 py-1.5 bg-blue-50 text-blue-600 rounded-lg hover:bg-blue-100 transition-colors text-sm font-bold">
                  <Plus className="w-4 h-4" /> {t('admin.editor.add_group')}
                </button>
              </div>

              <div className="space-y-6">
                {formData.schedule_details?.map((group, gIdx) => (
                  <div key={gIdx} className="bg-white dark:bg-slate-900 p-4 rounded-xl border border-slate-200 dark:border-slate-800 space-y-4">
                    <div className="flex items-center gap-4">
                      <input
                        className="flex-1 px-3 py-1.5 font-bold text-slate-800 dark:text-white border-b-2 border-transparent focus:border-blue-500 bg-transparent outline-none"
                        value={group.group}
                        onChange={e => updateGroupName(gIdx, e.target.value)}
                        placeholder={t('admin.editor.group_placeholder')}
                      />
                      <button type="button" onClick={() => removeScheduleGroup(gIdx)} className="p-1.5 text-red-500 hover:bg-red-50 rounded-lg transition-colors">
                        <Trash2 className="w-4 h-4" />
                      </button>
                    </div>

                    <div className="space-y-2">
                      {group.sessions?.map((session, sIdx) => (
                        <div key={sIdx} className="flex flex-wrap md:flex-nowrap gap-2 items-center bg-slate-50 dark:bg-slate-800 p-2 rounded-lg border border-slate-100 dark:border-slate-700">
                          <select
                            className="flex-1 min-w-[120px] p-1.5 text-sm border rounded bg-white dark:bg-slate-900 dark:text-white"
                            value={session.day}
                            onChange={e => updateSession(gIdx, sIdx, 'day', e.target.value)}
                          >
                            <option value={1}>{t('admin.editor.days.mon')}</option>
                            <option value={2}>{t('admin.editor.days.tue')}</option>
                            <option value={3}>{t('admin.editor.days.wed')}</option>
                            <option value={4}>{t('admin.editor.days.thu')}</option>
                            <option value={5}>{t('admin.editor.days.fri')}</option>
                            <option value={6}>{t('admin.editor.days.sat')}</option>
                          </select>
                          <div className="flex items-center gap-2">
                            <input
                              type="time"
                              className="p-1.5 text-sm border rounded bg-white dark:bg-slate-900 dark:text-white"
                              value={session.startTime}
                              onChange={e => updateSession(gIdx, sIdx, 'startTime', e.target.value)}
                            />
                            <span className="text-slate-400">a</span>
                            <input
                              type="time"
                              className="p-1.5 text-sm border rounded bg-white dark:bg-slate-900 dark:text-white"
                              value={session.endTime}
                              onChange={e => updateSession(gIdx, sIdx, 'endTime', e.target.value)}
                            />
                          </div>
                          <button type="button" onClick={() => removeSession(gIdx, sIdx)} className="p-1 text-slate-400 hover:text-red-500 transition-colors">
                            <X className="w-4 h-4" />
                          </button>
                        </div>
                      ))}
                      <button type="button" onClick={() => addSession(gIdx)} className="w-full py-2 border-2 border-dashed border-slate-200 dark:border-slate-700 rounded-lg text-xs font-medium text-slate-500 hover:border-blue-400 hover:text-blue-500 transition-all flex items-center justify-center gap-2 mt-2">
                        <Plus className="w-3 h-3" /> {t('admin.editor.add_session')}
                      </button>
                    </div>
                  </div>
                ))}
                {(!formData.schedule_details || formData.schedule_details.length === 0) && (
                  <div className="text-center py-8 bg-slate-100/50 dark:bg-slate-900/50 rounded-xl border-2 border-dashed border-slate-200 dark:border-slate-800">
                    <p className="text-sm text-slate-500 italic">{t('admin.editor.no_schedule')}</p>
                  </div>
                )}
              </div>
            </div>

            {/* Extra Fields */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="space-y-2">
                <label className="text-sm font-medium text-slate-700 dark:text-slate-300">{t('admin.editor.grades')} ({currentLang.toUpperCase()})</label>
                <input className="w-full px-4 py-2 rounded-lg border border-slate-300 dark:border-slate-600 dark:bg-slate-800 dark:text-white" value={getValue('grades')} onChange={e => handleChange('grades', e.target.value)} placeholder="Ex: 3r - 6è" />
              </div>
              <div className="space-y-2">
                <label className="text-sm font-medium text-slate-700 dark:text-slate-300">{t('admin.editor.place')}</label>
                <input className="w-full px-4 py-2 rounded-lg border border-slate-300 dark:border-slate-600 dark:bg-slate-800 dark:text-white" value={formData.place} onChange={e => handleChange('place', e.target.value)} placeholder="Ex: Gimnàs" />
              </div>
              <div className="space-y-2">
                <label className="text-sm font-medium text-slate-700 dark:text-slate-300">{t('admin.editor.color')}</label>
                <input className="w-full px-4 py-2 rounded-lg border border-slate-300 dark:border-slate-600 dark:bg-slate-800 dark:text-white" value={formData.color} onChange={e => handleChange('color', e.target.value)} placeholder="Ex: bg-blue-500" />
              </div>
              <div className="space-y-2">
                <label className="text-sm font-medium text-slate-700 dark:text-slate-300">{t('admin.editor.icon')}</label>
                <input className="w-full px-4 py-2 rounded-lg border border-slate-300 dark:border-slate-600 dark:bg-slate-800 dark:text-white" value={formData.category_icon} onChange={e => handleChange('category_icon', e.target.value)} placeholder="Ex: school" />
              </div>
            </div>

            <div className="space-y-2">
              <label className="text-sm font-medium text-slate-700 dark:text-slate-300">{t('inscription.activity_modal.note_label')} ({currentLang.toUpperCase()})</label>
              <textarea
                rows={2}
                className="w-full px-4 py-2 rounded-lg border border-slate-300 dark:border-slate-600 dark:bg-slate-800 dark:text-white focus:ring-2 focus:ring-blue-500"
                value={getValue('important_note')}
                onChange={e => handleChange('important_note', e.target.value)}
                placeholder="Important note..."
              />
            </div>

            <div className="flex items-center gap-2">
              <input type="checkbox" id="stem" checked={formData.is_stem_approved} onChange={e => handleChange('is_stem_approved', e.target.checked)} className="w-4 h-4 text-blue-600 rounded" />
              <label htmlFor="stem" className="text-sm text-slate-700 dark:text-slate-300">{t('admin.editor.stem')}</label>
            </div>

          </form>
        </div>

        {/* Footer */}
        <div className="p-6 border-t border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-800/50 flex justify-end gap-3">
          <button onClick={onClose} className="px-5 py-2.5 text-slate-600 font-medium hover:bg-slate-200 rounded-lg transition-colors">{t('admin.editor.cancel')}</button>
          <button
            form="activity-form"
            disabled={loading}
            className="px-5 py-2.5 bg-blue-600 text-white font-bold rounded-lg hover:bg-blue-700 shadow-lg shadow-blue-500/30 flex items-center gap-2 disabled:opacity-70 disabled:cursor-not-allowed"
          >
            {loading ? <Loader2 className="w-4 h-4 animate-spin" /> : <Save className="w-4 h-4" />}
            {t('admin.editor.save')}
          </button>
        </div>

      </motion.div>
    </div>
  );
}

import { useState, useEffect } from 'react';
import { X } from 'lucide-react';

import type { Inscription, InscriptionStudent } from '../../types/inscription';

interface EditInscriptionModalProps {
  inscription: Inscription;
  isOpen: boolean;
  onClose: () => void;
  onSave: (id: string, updates: Partial<Inscription>) => Promise<void>;
}

const COURSES = [
  'I3', 'I4', 'I5',
  '1r', '2n', '3r', '4t', '5è', '6è'
];

const AVAILABLE_ACTIVITIES = [
  'Acollida Matinal', 'Acollida Tarda',
  'Bàsquet', 'Futbol', 'Dansa', 'Patinatge',
  'Robòtica', 'Escacs', 'Anglès', 'Mewave',
  'Voleibol', 'Judo', 'Mecanografia', 'Teatre'
];

export function EditInscriptionModal({ inscription, isOpen, onClose, onSave }: EditInscriptionModalProps) {
  const [formData, setFormData] = useState<Inscription>(inscription);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    setFormData(inscription);
  }, [inscription]);

  if (!isOpen) return null;

  const handleParentChange = (field: keyof Inscription, value: any) => {
    setFormData((prev: Inscription) => ({ ...prev, [field]: value }));
  };

  const handleStudentChange = (index: number, field: keyof InscriptionStudent, value: any) => {
    const newStudents = [...(formData.students || [])];
    if (!newStudents[index]) return;
    newStudents[index] = { ...newStudents[index], [field]: value };
    setFormData((prev: Inscription) => ({ ...prev, students: newStudents }));
  };

  const toggleActivity = (studentIndex: number, activity: string) => {
    const newStudents = [...(formData.students || [])];
    const student = newStudents[studentIndex];
    if (!student) return;

    const currentActivities = student.activities || [];
    if (currentActivities.includes(activity)) {
      student.activities = currentActivities.filter((a: string) => a !== activity);
    } else {
      student.activities = [...currentActivities, activity];
    }

    setFormData(prev => ({ ...prev, students: newStudents }));
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    try {
      await onSave(formData.id, formData);
      onClose();
    } catch (error) {
      console.error(error);
      alert('Error al guardar los cambios');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="fixed inset-0 bg-black/50 flex items-center justify-center p-4 z-50 overflow-y-auto">
      <div className="bg-white rounded-xl shadow-xl w-full max-w-4xl my-8 flex flex-col max-h-[90vh]">
        <div className="p-6 border-b flex justify-between items-center sticky top-0 bg-white rounded-t-xl z-10">
          <h2 className="text-xl font-bold text-gray-900">Editar Inscripció</h2>
          <button onClick={onClose} className="text-gray-400 hover:text-gray-600">
            <X className="w-6 h-6" />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="p-6 overflow-y-auto flex-1 space-y-8">
          {/* Parent Section */}
          <section>
            <h3 className="text-lg font-semibold text-gray-800 mb-4 pb-2 border-b">Dades Familiars</h3>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Nom i Cognoms (Pare/Mare/Tutor)</label>
                <input
                  type="text"
                  required
                  value={formData.parent_name || ''}
                  onChange={e => handleParentChange('parent_name', e.target.value)}
                  className="w-full px-3 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">DNI/NIE</label>
                <input
                  type="text"
                  required
                  value={formData.parent_dni || ''}
                  onChange={e => handleParentChange('parent_dni', e.target.value)}
                  className="w-full px-3 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Email Principal</label>
                <input
                  type="email"
                  required
                  value={formData.parent_email_1 || ''}
                  onChange={e => handleParentChange('parent_email_1', e.target.value)}
                  className="w-full px-3 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Telèfon Principal</label>
                <input
                  type="tel"
                  required
                  value={formData.parent_phone_1 || ''}
                  onChange={e => handleParentChange('parent_phone_1', e.target.value)}
                  className="w-full px-3 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                />
              </div>
              <div className="flex items-center gap-2 mt-6">
                <input
                  type="checkbox"
                  id="afa_member"
                  checked={formData.afa_member || false}
                  onChange={e => handleParentChange('afa_member', e.target.checked)}
                  className="w-4 h-4 text-blue-600 rounded focus:ring-blue-500"
                />
                <label htmlFor="afa_member" className="font-medium text-gray-700">Soci de l'AFA</label>
              </div>
            </div>
          </section>

          {/* Students Section */}
          <section>
            <h3 className="text-lg font-semibold text-gray-800 mb-4 pb-2 border-b">Alumnes</h3>
            <div className="space-y-6">
              {(formData.students || []).map((student: InscriptionStudent, idx: number) => (
                <div key={idx} className="bg-slate-50 p-4 rounded-xl border border-slate-200">
                  <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-4">
                    <div>
                      <label className="block text-sm font-medium text-gray-700 mb-1">Nom</label>
                      <input
                        type="text"
                        value={student.name || ''}
                        onChange={e => handleStudentChange(idx, 'name', e.target.value)}
                        className="w-full px-3 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                      />
                    </div>
                    <div>
                      <label className="block text-sm font-medium text-gray-700 mb-1">Cognoms</label>
                      <input
                        type="text"
                        value={student.surname || ''}
                        onChange={e => handleStudentChange(idx, 'surname', e.target.value)}
                        className="w-full px-3 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                      />
                    </div>
                    <div>
                      <label className="block text-sm font-medium text-gray-700 mb-1">Curs</label>
                      <select
                        value={student.course || ''}
                        onChange={e => handleStudentChange(idx, 'course', e.target.value)}
                        className="w-full px-3 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                      >
                        <option value="">Seleccionar...</option>
                        {COURSES.map(c => <option key={c} value={c}>{c}</option>)}
                      </select>
                    </div>
                  </div>

                  {/* Activities Selection */}
                  <div>
                    <label className="block text-sm font-medium text-gray-700 mb-2">Activitats</label>
                    <div className="flex flex-wrap gap-2">
                      {AVAILABLE_ACTIVITIES.map(activity => {
                        const isSelected = (student.activities || []).includes(activity);
                        return (
                          <button
                            key={activity}
                            type="button"
                            onClick={() => toggleActivity(idx, activity)}
                            className={`px-3 py-1 rounded-full text-xs font-medium border transition-colors ${isSelected
                              ? 'bg-blue-100 text-blue-700 border-blue-200'
                              : 'bg-white text-gray-600 border-gray-200 hover:bg-gray-50'
                              }`}
                          >
                            {activity}
                          </button>
                        );
                      })}
                    </div>
                  </div>

                  {/* Status Toggle for Student */}
                  <div className="mt-4 pt-4 border-t border-slate-200 flex justify-end">
                    <label className="flex items-center gap-2 cursor-pointer text-sm text-slate-600 hover:text-slate-800">
                      <input
                        type="checkbox"
                        checked={student.suspended || false}
                        onChange={e => handleStudentChange(idx, 'suspended', e.target.checked)}
                        className="rounded text-red-500 focus:ring-red-500"
                      />
                      <span>Suspès temporalment</span>
                    </label>
                  </div>
                </div>
              ))}
            </div>
          </section>
        </form>

        <div className="p-6 border-t bg-gray-50 rounded-b-xl flex justify-end gap-3 sticky bottom-0 z-10">
          <button
            type="button"
            onClick={onClose}
            className="px-4 py-2 text-gray-700 hover:bg-gray-200 rounded-lg transition-colors"
          >
            Cancel·lar
          </button>
          <button
            onClick={handleSubmit}
            disabled={loading}
            className="px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors disabled:opacity-50"
          >
            {loading ? 'Guardant...' : 'Guardar Canvis'}
          </button>
        </div>
      </div>
    </div>
  );
}

import { useState, useEffect } from 'react';
import { X } from 'lucide-react';
import { supabase } from '../../lib/supabase';

interface Payment {
  id?: string;
  student_name: string;
  student_surname: string;
  course: string;
  activities: string[];
  amount: number;
  due_date: string;
  payment_date?: string | null;
  status: 'paid' | 'pending' | 'overdue';
  payment_month?: number;
  payment_year?: number;
  notes?: string;
  bank_reference?: string;
}

interface EditPaymentModalProps {
  payment?: Payment;
  isOpen: boolean;
  onClose: () => void;
  onSave: (payment: Payment) => Promise<void>;
}

export function EditPaymentModal({ payment, isOpen, onClose, onSave }: EditPaymentModalProps) {
  const [formData, setFormData] = useState<Payment>({
    student_name: '',
    student_surname: '',
    course: '',
    activities: [],
    amount: 0,
    due_date: new Date().toISOString().split('T')[0],
    status: 'pending'
  });
  const [loading, setLoading] = useState(false);
  const [students, setStudents] = useState<any[]>([]); // For search

  useEffect(() => {
    const fetchStudents = async () => {
      // Only fetch if we need to search (for new payments)
      if (students.length > 0) return;

      const { data } = await supabase
        .from('inscripcions')
        .select('students')
        .eq('status', 'alta');

      if (data) {
        // Flatten students
        const allStudents = data.flatMap((ins: any) => {
          return (ins.students || []).map((s: any) => ({
            name: s.name,
            surname: s.surname,
            course: s.course,
            activities: s.activities || []
          }));
        });
        setStudents(allStudents);
      }
    };

    if (payment) {
      setFormData({
        ...payment,
        payment_date: payment.payment_date
          ? new Date(payment.payment_date).toISOString().split('T')[0]
          : '',
        due_date: payment.due_date
          ? new Date(payment.due_date).toISOString().split('T')[0]
          : new Date().toISOString().split('T')[0]
      });
    } else {
      // Reset for new entry
      setFormData({
        student_name: '',
        student_surname: '',
        course: '',
        activities: [],
        amount: 0,
        due_date: new Date().toISOString().split('T')[0],
        status: 'pending',
        payment_month: new Date().getMonth() + 1,
        payment_year: new Date().getFullYear()
      });
      // Load students for autocomplete if creating
      if (isOpen) {
        fetchStudents();
      }
    }
  }, [payment, isOpen, students.length]);

  const handleStudentSelect = (e: React.ChangeEvent<HTMLSelectElement>) => {
    const idx = Number(e.target.value);
    if (idx >= 0 && students[idx]) {
      const s = students[idx];
      setFormData(prev => ({
        ...prev,
        student_name: s.name,
        student_surname: s.surname,
        course: s.course,
        activities: s.activities
      }));
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    try {
      await onSave(formData);
      onClose();
    } catch (error) {
      console.error(error);
      alert('Error al guardar el pagament');
    } finally {
      setLoading(false);
    }
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 bg-black/50 flex items-center justify-center p-4 z-50 overflow-y-auto">
      <div className="bg-white rounded-xl shadow-xl w-full max-w-2xl flex flex-col max-h-[90vh]">
        <div className="p-6 border-b flex justify-between items-center sticky top-0 bg-white rounded-t-xl z-10">
          <h2 className="text-xl font-bold text-gray-900">
            {payment ? 'Editar Pagament' : 'Registrar Nou Pagament'}
          </h2>
          <button onClick={onClose} className="text-gray-400 hover:text-gray-600">
            <X className="w-6 h-6" />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="p-6 overflow-y-auto flex-1 space-y-6">

          {/* Student Selection (Only if Creating) */}
          {!payment && (
            <div className="bg-slate-50 p-4 rounded-lg border border-slate-200">
              <label className="block text-sm font-medium text-gray-700 mb-2">Cercar Alumne (Opcional)</label>
              <select
                className="w-full px-3 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                onChange={handleStudentSelect}
                defaultValue=""
              >
                <option value="">-- Seleccionar Alumne --</option>
                {students.map((s, idx) => (
                  <option key={idx} value={idx}>
                    {s.name} {s.surname} ({s.course})
                  </option>
                ))}
              </select>
              <p className="text-xs text-gray-500 mt-1">Seleccionar un alumne omplirà automàticament les dades.</p>
            </div>
          )}

          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">Nom Alumne</label>
              <input
                type="text"
                required
                value={formData.student_name}
                onChange={e => setFormData({ ...formData, student_name: e.target.value })}
                className="w-full px-3 py-2 border rounded-lg focus:ring-blue-500 outline-none"
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">Cognoms</label>
              <input
                type="text"
                required
                value={formData.student_surname}
                onChange={e => setFormData({ ...formData, student_surname: e.target.value })}
                className="w-full px-3 py-2 border rounded-lg focus:ring-blue-500 outline-none"
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">Curs</label>
              <input
                type="text"
                value={formData.course}
                onChange={e => setFormData({ ...formData, course: e.target.value })}
                className="w-full px-3 py-2 border rounded-lg focus:ring-blue-500 outline-none"
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">Import (€)</label>
              <input
                type="number"
                step="0.01"
                required
                value={formData.amount}
                onChange={e => setFormData({ ...formData, amount: Number(e.target.value) })}
                className="w-full px-3 py-2 border rounded-lg focus:ring-blue-500 outline-none font-medium"
              />
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">Data Venciment</label>
              <input
                type="date"
                required
                value={formData.due_date}
                onChange={e => setFormData({ ...formData, due_date: e.target.value })}
                className="w-full px-3 py-2 border rounded-lg focus:ring-blue-500 outline-none"
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">Estat</label>
              <select
                value={formData.status}
                onChange={e => setFormData({ ...formData, status: e.target.value as any })}
                className={`w-full px-3 py-2 border rounded-lg focus:ring-blue-500 outline-none font-medium ${formData.status === 'paid' ? 'text-green-600 bg-green-50' :
                    formData.status === 'overdue' ? 'text-red-600 bg-red-50' : 'text-amber-600 bg-amber-50'
                  }`}
              >
                <option value="pending">Pendent</option>
                <option value="paid">Pagat</option>
                <option value="overdue">Vençut</option>
              </select>
            </div>
            {formData.status === 'paid' && (
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Data Pagament</label>
                <input
                  type="date"
                  value={formData.payment_date || ''}
                  onChange={e => setFormData({ ...formData, payment_date: e.target.value })}
                  className="w-full px-3 py-2 border rounded-lg focus:ring-blue-500 outline-none"
                />
              </div>
            )}
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Activitats (separades per coma)</label>
            <input
              type="text"
              value={formData.activities.join(', ')}
              onChange={e => setFormData({ ...formData, activities: e.target.value.split(',').map(s => s.trim()).filter(Boolean) })}
              className="w-full px-3 py-2 border rounded-lg focus:ring-blue-500 outline-none text-sm"
              placeholder="Ex: Futbol, Anglès"
            />
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Notes / Observacions</label>
            <textarea
              rows={3}
              value={formData.notes || ''}
              onChange={e => setFormData({ ...formData, notes: e.target.value })}
              className="w-full px-3 py-2 border rounded-lg focus:ring-blue-500 outline-none text-sm"
            />
          </div>

        </form>

        <div className="p-6 border-t bg-gray-50 rounded-b-xl flex justify-end gap-3 sticky bottom-0 z-10">
          <button
            type="button"
            onClick={onClose}
            className="px-4 py-2 text-gray-700 hover:bg-gray-200 rounded-lg transition-colors"
          >
            Cancel·lar
          </button>
          <button
            onClick={handleSubmit}
            disabled={loading}
            className="px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 transition-colors disabled:opacity-50"
          >
            {loading ? 'Guardant...' : 'Guardar Pagament'}
          </button>
        </div>
      </div>
    </div>
  );
}

import { useState, useEffect } from "react";
import { ShopService } from '../../features/shop/services/ShopService';
import type { ShopProduct, ShopVariant } from '../../features/shop/types/shop';
import { useTranslation } from "react-i18next";
import { X, Save, Loader2, Plus, Trash2, Package } from "lucide-react";
import { motion, AnimatePresence } from "framer-motion";
import { sortSizes } from "../../utils/productUtils";
import { ConfigService, type ShopConfig } from "../../services/ConfigService";

interface ProductEditorModalProps {
  isOpen: boolean;
  onClose: () => void;
  product?: ShopProduct | null;
  onSaved: () => void;
}

export function ProductEditorModal({ isOpen, onClose, product, onSaved }: ProductEditorModalProps) {
  const { t } = useTranslation();
  const [formData, setFormData] = useState<Partial<ShopProduct>>({
    category: 'uniforme',
    name: '',
    description: '',
  });
  const [variants, setVariants] = useState<Partial<ShopVariant>[]>([]);
  const [loading, setLoading] = useState(false);
  const [currentLang, setCurrentLang] = useState<'es' | 'ca' | 'en'>('es');
  const [shopConfig, setShopConfig] = useState<ShopConfig | null>(null);

  useEffect(() => {
    const fetchConfig = async () => {
      const config = await ConfigService.getShopConfig();
      if (config) setShopConfig(config);
    };
    fetchConfig();
  }, []);

  useEffect(() => {
    if (product) {
      setFormData(product);
      setVariants(sortSizes(product.variants || []));
    } else {
      setFormData({
        category: 'uniforme',
        name: '',
        description: '',
      });
      setVariants([
        { size: 'Única', price_member: 0, price_non_member: 0, stock: 0 }
      ]);
    }
  }, [product, isOpen]);

  if (!isOpen) return null;

  const handleChange = <K extends keyof ShopProduct>(field: K, value: ShopProduct[K]) => {
    const translatableFields = ['name', 'description'];

    if (translatableFields.includes(field)) {
      const langKey = `${field}_${currentLang}` as keyof ShopProduct;
      setFormData(prev => ({
        ...prev,
        [langKey]: value,
        ...(currentLang === 'es' ? { [field]: value } : {})
      }));
    } else {
      setFormData(prev => ({ ...prev, [field]: value }));
    }
  };

  const handleVariantChange = <K extends keyof ShopVariant>(index: number, field: K, value: ShopVariant[K]) => {
    setVariants(prev => {
      const newVariants = [...prev];
      newVariants[index] = { ...newVariants[index], [field]: value };
      return newVariants;
    });
  };

  const addVariant = () => {
    setVariants(prev => [...prev, { size: '', price_member: 0, price_non_member: 0, stock: 0 }]);
  };

  const removeVariant = (index: number) => {
    setVariants(prev => prev.filter((_, i) => i !== index));
  };

  const getValue = (field: keyof ShopProduct): string => {
    const langKey = `${field}_${currentLang}` as keyof ShopProduct;
    const val = formData[langKey as keyof typeof formData];
    if (val !== undefined && val !== null) return String(val);

    return currentLang === 'es' && formData[field] ? String(formData[field]) : '';
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    try {
      let savedProduct;
      if (product?.id) {
        savedProduct = await ShopService.updateProduct(product.id, formData);
      } else {
        savedProduct = await ShopService.createProduct(formData);
      }

      const productId = product?.id || savedProduct?.id;
      if (!productId) throw new Error("Could not determine product ID");

      // Handle variants (sort them before processing)
      const sortedCurrentVariants = sortSizes<Partial<ShopVariant>>(variants);

      // 1. Get original variants if updating
      const originalVariants = product?.variants || [];
      const originalIds = originalVariants.map(v => v.id);
      const currentIds = sortedCurrentVariants.map(v => v.id).filter(Boolean);

      // 2. Delete variants that are no longer present
      const toDelete = originalIds.filter(id => !currentIds.includes(id));
      for (const id of toDelete) {
        await ShopService.deleteVariant(id);
      }

      // 3. Update or Create variants
      for (const variant of sortedCurrentVariants) {
        if (variant.id) {
          await ShopService.updateVariant(variant.id, variant);
        } else {
          await ShopService.createVariant({ ...variant, product_id: productId });
        }
      }

      onSaved();
      onClose();
    } catch (error) {
      console.error("Failed to save product", error);
      alert(t('common.error_save'));
    } finally {
      setLoading(false);
    }
  };

  const handleDeleteProduct = async () => {
    if (!product?.id) return;
    if (!window.confirm(t('common.confirm_delete' as any) || 'Estàs segur que vols eliminar aquest producte?')) return;

    setLoading(true);
    try {
      await ShopService.deleteProduct(product.id);
      onSaved();
      onClose();
    } catch (error) {
      console.error("Failed to delete product", error);
      alert(t('common.error_delete' as any) || 'Error al eliminar el producte');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-md p-4">
      <motion.div
        initial={{ opacity: 0, scale: 0.95, y: 20 }}
        animate={{ opacity: 1, scale: 1, y: 0 }}
        exit={{ opacity: 0, scale: 0.95, y: 20 }}
        className="bg-white dark:bg-slate-900 w-full max-w-3xl max-h-[90vh] rounded-2xl shadow-2xl flex flex-col overflow-hidden border border-slate-200 dark:border-slate-800"
      >
        {/* Header */}
        <div className="flex justify-between items-center p-6 border-b border-slate-100 dark:border-slate-800">
          <div className="flex items-center gap-3">
            <div className="p-2 bg-blue-50 dark:bg-blue-900/30 rounded-lg">
              <Package className="w-5 h-5 text-blue-600 dark:text-blue-400" />
            </div>
            <h2 className="text-xl font-bold dark:text-white">
              {product ? 'Editar Producte' : 'Nou Producte'}
            </h2>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-full transition-colors">
            <X className="w-5 h-5 text-slate-500" />
          </button>
        </div>

        {/* Content */}
        <div className="flex-1 overflow-y-auto p-6 space-y-8">

          {/* Section: Basic Info */}
          <section className="space-y-6">
            <div className="flex items-center gap-2 text-sm font-semibold text-slate-400 uppercase tracking-wider">
              <span>Informació Bàsica</span>
              <div className="flex-1 h-[1px] bg-slate-100 dark:bg-slate-800"></div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="space-y-2">
                <label className="text-sm font-medium text-slate-700 dark:text-slate-300">Categoria</label>
                <select
                  value={formData.category}
                  onChange={e => handleChange('category', e.target.value as 'uniforme' | 'accessoris')}
                  className="w-full px-4 py-2.5 rounded-xl border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 dark:text-white focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 outline-none transition-all"
                >
                  {shopConfig?.categories.map(cat => (
                    <option key={cat.id} value={cat.id}>
                      {cat.translations[currentLang] || cat.translations['ca']}
                    </option>
                  ))}
                  {!shopConfig && (
                    <>
                      <option value="uniforme">Uniforme</option>
                      <option value="accessoris">Accessoris</option>
                    </>
                  )}
                </select>
              </div>
              <div className="space-y-2">
                <label className="text-sm font-medium text-slate-700 dark:text-slate-300">URL Imatge (opcional)</label>
                <input
                  type="text"
                  value={formData.image_url || ''}
                  onChange={e => handleChange('image_url', e.target.value)}
                  placeholder="https://..."
                  className="w-full px-4 py-2.5 rounded-xl border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 dark:text-white focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 outline-none transition-all"
                />
              </div>
            </div>

            {/* Language Tabs for Name/Description */}
            <div className="space-y-4">
              <div className="flex gap-1 p-1 bg-slate-100 dark:bg-slate-800 w-fit rounded-lg">
                {(['es', 'ca', 'en'] as const).map(lang => (
                  <button
                    key={lang}
                    type="button"
                    onClick={() => setCurrentLang(lang)}
                    className={`px-4 py-1.5 text-sm font-bold rounded-md transition-all ${currentLang === lang ? 'bg-white dark:bg-slate-700 text-blue-600 dark:text-blue-400 shadow-sm' : 'text-slate-500 hover:text-slate-700 dark:hover:text-slate-300'}`}
                  >
                    {lang === 'es' ? 'ES' : lang === 'ca' ? 'CA' : 'EN'}
                  </button>
                ))}
              </div>

              <div className="space-y-4 bg-slate-50 dark:bg-slate-800/50 p-4 rounded-2xl border border-slate-100 dark:border-slate-800">
                <div className="space-y-2">
                  <label className="text-sm font-medium text-slate-700 dark:text-slate-300">Nom del Producte ({currentLang.toUpperCase()})</label>
                  <input
                    required={currentLang === 'es'}
                    className="w-full px-4 py-2.5 rounded-xl border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 dark:text-white focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 outline-none transition-all"
                    value={getValue('name')}
                    onChange={e => handleChange('name', e.target.value)}
                    placeholder={currentLang !== 'es' ? '(Opcional) Deixar buit per usar defecte' : 'Ex: Samarreta Oficial'}
                  />
                </div>

                <div className="space-y-2">
                  <label className="text-sm font-medium text-slate-700 dark:text-slate-300">Descripció ({currentLang.toUpperCase()})</label>
                  <textarea
                    rows={3}
                    className="w-full px-4 py-2.5 rounded-xl border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 dark:text-white focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 outline-none transition-all resize-none"
                    value={getValue('description')}
                    onChange={e => handleChange('description', e.target.value)}
                    placeholder="..."
                  />
                </div>
              </div>
            </div>
          </section>

          {/* Section: Variants (Sizes & Prices) */}
          <section className="space-y-4">
            <div className="flex items-center justify-between">
              <div className="flex items-center gap-2 text-sm font-semibold text-slate-400 uppercase tracking-wider">
                <span>Talles i Preus</span>
                <div className="w-24 h-[1px] bg-slate-100 dark:bg-slate-800"></div>
              </div>
              <button
                type="button"
                onClick={addVariant}
                className="flex items-center gap-1.5 text-sm font-bold text-blue-600 hover:text-blue-700 dark:text-blue-400"
              >
                <Plus className="w-4 h-4" />
                Afegir Talla
              </button>
            </div>

            <div className="space-y-3">
              <AnimatePresence mode="popLayout">
                {variants.map((variant, index) => (
                  <motion.div
                    key={index}
                    layout
                    initial={{ opacity: 0, x: -10 }}
                    animate={{ opacity: 1, x: 0 }}
                    exit={{ opacity: 0, x: 10 }}
                    className="grid grid-cols-1 md:grid-cols-5 gap-3 p-4 bg-white dark:bg-slate-800/30 rounded-xl border border-slate-100 dark:border-slate-800 items-end"
                  >
                    <div className="md:col-span-1 space-y-1.5">
                      <label className="text-[10px] font-bold text-slate-400 uppercase">Talla</label>
                      <input
                        type="text"
                        value={variant.size}
                        onChange={e => handleVariantChange(index, 'size', e.target.value)}
                        placeholder="XL, 38..."
                        className="w-full px-3 py-2 rounded-lg border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 text-sm outline-none focus:border-blue-500"
                      />
                    </div>
                    <div className="space-y-1.5">
                      <label className="text-[10px] font-bold text-slate-400 uppercase">Preu Soci</label>
                      <div className="relative">
                        <input
                          type="number"
                          value={variant.price_member}
                          onChange={e => handleVariantChange(index, 'price_member', parseFloat(e.target.value))}
                          className="w-full pl-3 pr-6 py-2 rounded-lg border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 text-sm outline-none focus:border-blue-500"
                        />
                        <span className="absolute right-2 top-1/2 -translate-y-1/2 text-xs text-slate-400">€</span>
                      </div>
                    </div>
                    <div className="space-y-1.5">
                      <label className="text-[10px] font-bold text-slate-400 uppercase">Preu No Soci</label>
                      <div className="relative">
                        <input
                          type="number"
                          value={variant.price_non_member}
                          onChange={e => handleVariantChange(index, 'price_non_member', parseFloat(e.target.value))}
                          className="w-full pl-3 pr-6 py-2 rounded-lg border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 text-sm outline-none focus:border-blue-500"
                        />
                        <span className="absolute right-2 top-1/2 -translate-y-1/2 text-xs text-slate-400">€</span>
                      </div>
                    </div>
                    <div className="space-y-1.5">
                      <label className="text-[10px] font-bold text-slate-400 uppercase">Estoc</label>
                      <input
                        type="number"
                        value={variant.stock}
                        onChange={e => handleVariantChange(index, 'stock', parseInt(e.target.value))}
                        className="w-full px-3 py-2 rounded-lg border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 text-sm outline-none focus:border-blue-500"
                      />
                    </div>
                    <div className="flex justify-end pb-1">
                      <button
                        type="button"
                        onClick={() => removeVariant(index)}
                        className="p-2 text-slate-400 hover:text-red-500 hover:bg-red-50 dark:hover:bg-red-900/20 rounded-lg transition-all"
                      >
                        <Trash2 className="w-4 h-4" />
                      </button>
                    </div>
                  </motion.div>
                ))}
              </AnimatePresence>

              {variants.length === 0 && (
                <div className="text-center py-8 bg-slate-50 dark:bg-slate-800/20 rounded-2xl border border-dashed border-slate-200 dark:border-slate-700">
                  <p className="text-sm text-slate-500">No hi ha talles definides. Afegeix-ne una.</p>
                </div>
              )}
            </div>
          </section>
        </div>

        {/* Footer */}
        <div className="p-6 border-t border-slate-100 dark:border-slate-800 bg-slate-50 dark:bg-slate-900/50 flex justify-between items-center">
          {product?.id ? (
            <button
              type="button"
              onClick={handleDeleteProduct}
              className="text-sm font-bold text-red-500 hover:text-red-600 px-4 py-2 hover:bg-red-50 dark:hover:bg-red-900/10 rounded-lg transition-all flex items-center gap-2"
            >
              <Trash2 className="w-4 h-4" />
              Eliminar Producte
            </button>
          ) : <div />}

          <div className="flex gap-3">
            <button
              onClick={onClose}
              className="px-5 py-2.5 text-sm font-bold text-slate-600 hover:bg-slate-200 dark:text-slate-400 dark:hover:bg-slate-800 rounded-xl transition-all"
            >
              Cancel·lar
            </button>
            <button
              onClick={handleSubmit}
              disabled={loading || !formData.name}
              className="px-6 py-2.5 bg-blue-600 text-white font-bold rounded-xl hover:bg-blue-700 shadow-lg shadow-blue-500/20 flex items-center gap-2 disabled:opacity-50 disabled:cursor-not-allowed transition-all active:scale-95"
            >
              {loading ? <Loader2 className="w-4 h-4 animate-spin" /> : <Save className="w-4 h-4" />}
              {product ? 'Guardar Canvis' : 'Crear Producte'}
            </button>
          </div>
        </div>

      </motion.div>
    </div>
  );
}

import { useTranslation } from 'react-i18next';
import { Trash2, X } from 'lucide-react';
import { EVENT_TYPES } from '../../../services/admin/AdminCalendarService';
import type { EventFormData, CalendarEvent } from '../../../services/admin/AdminCalendarService';

interface EventFormModalProps {
    isOpen: boolean;
    onClose: () => void;
    onSave: () => void;
    onDelete?: (id: string) => void;
    formData: EventFormData;
    setFormData: React.Dispatch<React.SetStateAction<EventFormData>>;
    editingEvent: CalendarEvent | null;
    saving: boolean;
}

export function EventFormModal({
    isOpen,
    onClose,
    onSave,
    onDelete,
    formData,
    setFormData,
    editingEvent,
    saving
}: EventFormModalProps) {
    const { t } = useTranslation();

    if (!isOpen) return null;

    return (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm flex items-center justify-center z-50 p-4 animate-in fade-in duration-200">
            <div className="bg-white dark:bg-slate-900 rounded-[2.5rem] shadow-2xl w-full max-w-lg max-h-[90vh] overflow-hidden border border-slate-200 dark:border-slate-800 animate-in zoom-in-95 duration-200">
                <div className="p-8 border-b border-slate-100 dark:border-slate-800 flex justify-between items-center">
                    <h2 className="text-2xl font-black text-slate-900 dark:text-white tracking-tight">
                        {editingEvent ? t('admin.calendar.edit_event') : t('admin.calendar.new_event')}
                    </h2>
                    <button
                        onClick={onClose}
                        className="p-2 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-full transition-colors"
                    >
                        <X className="w-6 h-6 text-slate-400" />
                    </button>
                </div>

                <div className="p-8 space-y-6 overflow-y-auto max-h-[calc(90vh-200px)] custom-scrollbar">
                    <div className="space-y-2">
                        <label className="text-xs font-black uppercase tracking-widest text-slate-400 ml-1">
                            {t('admin.calendar.field_title')} *
                        </label>
                        <input
                            type="text"
                            value={formData.title}
                            onChange={e => setFormData(prev => ({ ...prev, title: e.target.value }))}
                            className="w-full px-6 py-4 bg-slate-50 dark:bg-slate-950 border border-transparent focus:border-primary dark:focus:border-primary rounded-2xl outline-none transition-all text-slate-900 dark:text-white font-medium shadow-inner"
                            placeholder="Ej. Fiesta de Fin de Curso"
                        />
                    </div>

                    <div className="grid grid-cols-2 gap-6">
                        <div className="space-y-2">
                            <label className="text-xs font-black uppercase tracking-widest text-slate-400 ml-1">
                                {t('admin.calendar.field_date')} *
                            </label>
                            <input
                                type="date"
                                value={formData.event_date}
                                onChange={e => setFormData(prev => ({ ...prev, event_date: e.target.value }))}
                                className="w-full px-6 py-4 bg-slate-50 dark:bg-slate-950 border border-transparent focus:border-primary dark:focus:border-primary rounded-2xl outline-none transition-all text-slate-900 dark:text-white font-medium shadow-inner"
                            />
                        </div>
                        <div className="space-y-2">
                            <label className="text-xs font-black uppercase tracking-widest text-slate-400 ml-1">
                                {t('admin.calendar.field_type')}
                            </label>
                            <select
                                value={formData.event_type}
                                onChange={e => {
                                    const type = EVENT_TYPES.find(t => t.value === e.target.value);
                                    setFormData(prev => ({
                                        ...prev,
                                        event_type: e.target.value as any,
                                        color: type?.color || prev.color
                                    }));
                                }}
                                className="w-full px-6 py-4 bg-slate-50 dark:bg-slate-950 border border-transparent focus:border-primary dark:focus:border-primary rounded-2xl outline-none transition-all text-slate-900 dark:text-white font-medium shadow-inner appearance-none cursor-pointer"
                            >
                                {EVENT_TYPES.map(type => (
                                    <option key={type.value} value={type.value}>{type.label}</option>
                                ))}
                            </select>
                        </div>
                    </div>

                    <div className="flex items-center gap-3 p-4 bg-slate-50 dark:bg-slate-800/50 rounded-2xl">
                        <div className="relative inline-flex items-center cursor-pointer">
                            <input
                                type="checkbox"
                                id="allDay"
                                checked={formData.all_day}
                                onChange={e => setFormData(prev => ({ ...prev, all_day: e.target.checked }))}
                                className="sr-only peer"
                            />
                            <div className="w-11 h-6 bg-slate-200 peer-focus:outline-none rounded-full peer dark:bg-slate-700 peer-checked:after:translate-x-full peer-checked:after:border-white after:content-[''] after:absolute after:top-[2px] after:left-[2px] after:bg-white after:border-slate-300 after:border after:rounded-full after:h-5 after:w-5 after:transition-all dark:border-slate-600 peer-checked:bg-primary"></div>
                        </div>
                        <label htmlFor="allDay" className="text-sm font-bold text-slate-700 dark:text-slate-300 cursor-pointer">
                            {t('admin.calendar.all_day')}
                        </label>
                    </div>

                    {!formData.all_day && (
                        <div className="grid grid-cols-2 gap-6 animate-in slide-in-from-top-2 duration-200">
                            <div className="space-y-2">
                                <label className="text-xs font-black uppercase tracking-widest text-slate-400 ml-1">
                                    {t('admin.calendar.field_start_time')}
                                </label>
                                <input
                                    type="time"
                                    value={formData.start_time || ''}
                                    onChange={e => setFormData(prev => ({ ...prev, start_time: e.target.value }))}
                                    className="w-full px-6 py-4 bg-slate-50 dark:bg-slate-950 border border-transparent focus:border-primary dark:focus:border-primary rounded-2xl outline-none transition-all text-slate-900 dark:text-white font-medium shadow-inner"
                                />
                            </div>
                            <div className="space-y-2">
                                <label className="text-xs font-black uppercase tracking-widest text-slate-400 ml-1">
                                    {t('admin.calendar.field_end_time')}
                                </label>
                                <input
                                    type="time"
                                    value={formData.end_time || ''}
                                    onChange={e => setFormData(prev => ({ ...prev, end_time: e.target.value }))}
                                    className="w-full px-6 py-4 bg-slate-50 dark:bg-slate-950 border border-transparent focus:border-primary dark:focus:border-primary rounded-2xl outline-none transition-all text-slate-900 dark:text-white font-medium shadow-inner"
                                />
                            </div>
                        </div>
                    )}

                    <div className="space-y-2">
                        <label className="text-xs font-black uppercase tracking-widest text-slate-400 ml-1">
                            {t('admin.calendar.field_location')}
                        </label>
                        <input
                            type="text"
                            value={formData.location || ''}
                            onChange={e => setFormData(prev => ({ ...prev, location: e.target.value }))}
                            className="w-full px-6 py-4 bg-slate-50 dark:bg-slate-950 border border-transparent focus:border-primary dark:focus:border-primary rounded-2xl outline-none transition-all text-slate-900 dark:text-white font-medium shadow-inner"
                            placeholder="Ej. Patio de la escuela"
                        />
                    </div>

                    <div className="space-y-2">
                        <label className="text-xs font-black uppercase tracking-widest text-slate-400 ml-1">
                            {t('admin.calendar.field_description')}
                        </label>
                        <textarea
                            value={formData.description || ''}
                            onChange={e => setFormData(prev => ({ ...prev, description: e.target.value }))}
                            rows={3}
                            className="w-full px-6 py-4 bg-slate-50 dark:bg-slate-950 border border-transparent focus:border-primary dark:focus:border-primary rounded-2xl outline-none transition-all text-slate-900 dark:text-white font-medium shadow-inner resize-none"
                            placeholder="Añade más detalles sobre el evento..."
                        />
                    </div>

                    <div className="space-y-3">
                        <label className="text-xs font-black uppercase tracking-widest text-slate-400 ml-1">
                            {t('admin.calendar.field_color')}
                        </label>
                        <div className="flex flex-wrap gap-3">
                            {['#3b82f6', '#8b5cf6', '#ec4899', '#ef4444', '#22c55e', '#f59e0b', '#0ea5e9', '#6366f1'].map(color => (
                                <button
                                    key={color}
                                    type="button"
                                    onClick={() => setFormData(prev => ({ ...prev, color }))}
                                    className={`w-10 h-10 rounded-full transition-all duration-300 ${formData.color === color
                                        ? 'ring-4 ring-offset-4 ring-primary scale-110 shadow-lg'
                                        : 'hover:scale-110 opacity-80 hover:opacity-100'
                                        }`}
                                    style={{ backgroundColor: color }}
                                />
                            ))}
                        </div>
                    </div>
                </div>

                <div className="p-8 border-t border-slate-100 dark:border-slate-800 flex justify-between gap-4 bg-slate-50/50 dark:bg-slate-900/50">
                    {editingEvent && onDelete && (
                        <button
                            onClick={() => onDelete(editingEvent.id)}
                            className="px-6 py-4 text-red-500 font-bold hover:bg-red-50 dark:hover:bg-red-950/30 rounded-2xl transition-all flex items-center gap-2"
                        >
                            <Trash2 className="w-5 h-5" />
                            <span className="hidden sm:inline">{t('common.delete')}</span>
                        </button>
                    )}
                    <div className="flex gap-4 ml-auto w-full sm:w-auto">
                        <button
                            onClick={onClose}
                            className="flex-1 sm:flex-none px-8 py-4 bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-2xl text-slate-700 dark:text-slate-300 font-bold hover:bg-slate-50 dark:hover:bg-slate-700 transition-all shadow-sm"
                        >
                            {t('common.cancel')}
                        </button>
                        <button
                            onClick={onSave}
                            disabled={saving}
                            className="flex-1 sm:flex-none px-8 py-4 bg-primary text-white rounded-2xl font-black hover:bg-primary/90 transition-all disabled:opacity-50 shadow-xl shadow-primary/20 active:scale-95"
                        >
                            {saving ? t('common.saving') : t('common.save')}
                        </button>
                    </div>
                </div>
            </div>
        </div>
    );
}

import { useEffect } from 'react';
import { useLocation } from 'react-router-dom';

declare global {
    interface Window {
        gtag: (...args: any[]) => void;
    }
}

export function GoogleAnalytics() {
    const location = useLocation();

    useEffect(() => {
        if (typeof window.gtag === 'function') {
            window.gtag('config', 'G-2DMTERT1FH', {
                page_path: location.pathname + location.search,
            });
        }
    }, [location]);

    return null;
}

