import { useState, useEffect } from 'react';
import { X, Save, AlertCircle, CheckCircle2, Languages, Plus, Trash2 } from 'lucide-react';
import { ConfigService, type AboutConfig } from '../../services/ConfigService';

interface AboutSettingsModalProps {
    isOpen: boolean;
    onClose: () => void;
    currentConfig: AboutConfig | null;
    onUpdate: (newConfig: AboutConfig) => void;
}

type LangCode = 'ca' | 'es' | 'en';

export function AboutSettingsModal({ isOpen, onClose, currentConfig, onUpdate }: AboutSettingsModalProps) {
    const [activeLang, setActiveLang] = useState<LangCode>('ca');
    const [translations, setTranslations] = useState<AboutConfig['translations']>({
        ca: { text: '', functions: [] },
        es: { text: '', functions: [] },
        en: { text: '', functions: [] }
    });

    const [saving, setSaving] = useState(false);
    const [error, setError] = useState<string | null>(null);
    const [success, setSuccess] = useState(false);

    useEffect(() => {
        if (currentConfig?.translations) {
            setTranslations(currentConfig.translations);
        } else if (currentConfig) {
            // Migration for old structure if it exists
            const oldConfig = currentConfig as any;
            setTranslations({
                ca: { text: oldConfig.text || '', functions: oldConfig.functions || [] },
                es: { text: oldConfig.text || '', functions: oldConfig.functions || [] },
                en: { text: oldConfig.text || '', functions: oldConfig.functions || [] }
            });
        }
    }, [currentConfig, isOpen]);

    if (!isOpen) return null;

    const handleTextChange = (value: string) => {
        setTranslations(prev => ({
            ...prev,
            [activeLang]: { ...prev[activeLang], text: value }
        }));
    };

    const handleFunctionChange = (index: number, value: string) => {
        const newFunctions = [...translations[activeLang].functions];
        newFunctions[index] = value;
        setTranslations(prev => ({
            ...prev,
            [activeLang]: { ...prev[activeLang], functions: newFunctions }
        }));
    };

    const addFunction = () => {
        setTranslations(prev => ({
            ...prev,
            [activeLang]: {
                ...prev[activeLang],
                functions: [...prev[activeLang].functions, '']
            }
        }));
    };

    const removeFunction = (index: number) => {
        setTranslations(prev => ({
            ...prev,
            [activeLang]: {
                ...prev[activeLang],
                functions: prev[activeLang].functions.filter((_, i) => i !== index)
            }
        }));
    };

    const handleSave = async (e: React.FormEvent) => {
        e.preventDefault();
        setSaving(true);
        setError(null);
        setSuccess(false);

        try {
            const newConfig: AboutConfig = { translations };
            await ConfigService.updateAboutConfig(newConfig);
            onUpdate(newConfig);
            setSuccess(true);
            setTimeout(() => {
                onClose();
                setSuccess(false);
            }, 2000);
        } catch (err: any) {
            console.error(err);
            setError(err.message || "Error al guardar la configuració");
        } finally {
            setSaving(false);
        }
    };

    const langTabs: { code: LangCode; label: string }[] = [
        { code: 'ca', label: 'Català' },
        { code: 'es', label: 'Castellano' },
        { code: 'en', label: 'English' }
    ];

    return (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm animate-in fade-in">
            <div className="bg-white dark:bg-slate-900 w-full max-w-2xl rounded-3xl shadow-2xl overflow-hidden animate-in zoom-in-95 duration-200 flex flex-col max-h-[90vh]">
                <div className="flex items-center justify-between p-6 border-b border-slate-100 dark:border-slate-800 shrink-0">
                    <h2 className="text-xl font-bold text-slate-900 dark:text-white flex items-center gap-2">
                        Configuració "Què fa l'AFA?"
                    </h2>
                    <button onClick={onClose} className="p-2 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-full transition-colors text-slate-500">
                        <X size={20} />
                    </button>
                </div>

                <div className="flex bg-slate-50 dark:bg-slate-800/50 p-1 m-6 mb-0 rounded-2xl shrink-0">
                    {langTabs.map((tab) => (
                        <button
                            key={tab.code}
                            onClick={() => setActiveLang(tab.code)}
                            className={`flex-1 flex items-center justify-center gap-2 py-2.5 rounded-xl text-sm font-bold transition-all ${activeLang === tab.code
                                ? 'bg-white dark:bg-slate-700 text-primary shadow-sm'
                                : 'text-slate-500 hover:text-slate-700 dark:hover:text-slate-300'
                                }`}
                        >
                            <Languages size={16} />
                            {tab.label}
                        </button>
                    ))}
                </div>

                <form onSubmit={handleSave} className="p-6 pt-4 space-y-6 overflow-y-auto">
                    <div className="space-y-2 text-left">
                        <label className="block text-sm font-bold text-slate-700 dark:text-slate-200">
                            Text de presentació ({activeLang.toUpperCase()})
                        </label>
                        <textarea
                            value={translations[activeLang].text}
                            onChange={(e) => handleTextChange(e.target.value)}
                            rows={6}
                            className="w-full px-4 py-3 rounded-xl border border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-800 text-slate-900 dark:text-white outline-none focus:ring-2 focus:ring-primary transition-all font-medium resize-none text-sm"
                            placeholder="Escriu aquí la descripció de l'AFA..."
                        />
                    </div>

                    <div className="space-y-4 text-left">
                        <div className="flex items-center justify-between">
                            <label className="block text-sm font-bold text-slate-700 dark:text-slate-200">
                                Funcions principals ({activeLang.toUpperCase()})
                            </label>
                            <button
                                type="button"
                                onClick={addFunction}
                                className="text-xs bg-primary/10 text-primary hover:bg-primary hover:text-white px-3 py-1.5 rounded-lg font-bold transition-all flex items-center gap-1"
                            >
                                <Plus size={14} />
                                Afegir funció
                            </button>
                        </div>

                        <div className="space-y-3">
                            {translations[activeLang].functions.map((func, index) => (
                                <div key={index} className="flex gap-2">
                                    <input
                                        type="text"
                                        value={func}
                                        onChange={(e) => handleFunctionChange(index, e.target.value)}
                                        className="flex-1 px-4 py-2.5 rounded-xl border border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-800 text-slate-900 dark:text-white outline-none focus:ring-2 focus:ring-primary transition-all font-medium text-sm"
                                        placeholder={`Funció ${index + 1}`}
                                    />
                                    <button
                                        type="button"
                                        onClick={() => removeFunction(index)}
                                        className="p-2.5 text-red-500 hover:bg-red-50 dark:hover:bg-red-900/20 rounded-xl transition-colors shrink-0"
                                    >
                                        <Trash2 size={18} />
                                    </button>
                                </div>
                            ))}
                            {translations[activeLang].functions.length === 0 && (
                                <p className="text-center py-4 text-slate-400 text-xs italic bg-slate-50 dark:bg-slate-800/50 rounded-xl border border-dashed border-slate-200 dark:border-slate-700">
                                    No hi ha funcions definides per a aquest idioma.
                                </p>
                            )}
                        </div>
                    </div>

                    {error && (
                        <div className="p-3 bg-red-50 dark:bg-red-900/10 border border-red-100 dark:border-red-900/20 text-red-600 dark:text-red-400 rounded-xl flex items-center gap-2 text-sm">
                            <AlertCircle size={16} />
                            <p>{error}</p>
                        </div>
                    )}

                    {success && (
                        <div className="p-3 bg-green-50 dark:bg-green-900/10 border border-green-100 dark:border-green-900/20 text-green-600 dark:text-green-400 rounded-xl flex items-center gap-2 text-sm">
                            <CheckCircle2 size={16} />
                            <p>Configuració guardada correctament!</p>
                        </div>
                    )}
                </form>

                <div className="p-6 border-t border-slate-100 dark:border-slate-800 flex gap-3 shrink-0">
                    <button
                        type="button"
                        onClick={onClose}
                        className="flex-1 px-6 py-3 rounded-xl font-bold text-slate-600 dark:text-slate-400 border border-slate-200 dark:border-slate-700 hover:bg-slate-50 dark:hover:bg-slate-800 transition-colors"
                    >
                        Cancel·lar
                    </button>
                    <button
                        onClick={handleSave}
                        disabled={saving}
                        className="flex-[2] bg-primary hover:bg-primary/90 text-white font-bold px-6 py-3 rounded-xl shadow-lg shadow-primary/30 transition-all active:scale-95 disabled:opacity-50 flex items-center justify-center gap-2"
                    >
                        {saving ? (
                            <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin"></div>
                        ) : (
                            <>
                                <Save size={18} />
                                Guardar Canvis
                            </>
                        )}
                    </button>
                </div>
            </div>
        </div>
    );
}

import { useState } from 'react';
import { X, Upload, Save, AlertCircle, CheckCircle2 } from 'lucide-react';
import { ConfigService, type HeroConfig } from '../../services/ConfigService';

interface HeroSettingsModalProps {
    isOpen: boolean;
    onClose: () => void;
    currentConfig: HeroConfig | null;
    onUpdate: (newConfig: HeroConfig) => void;
}

export function HeroSettingsModal({ isOpen, onClose, currentConfig, onUpdate }: HeroSettingsModalProps) {
    const [imageFile, setImageFile] = useState<File | null>(null);
    const [imagePreview, setImagePreview] = useState<string | null>(currentConfig?.image_url || null);
    const [title, setTitle] = useState(currentConfig?.title || '');
    const [saving, setSaving] = useState(false);
    const [error, setError] = useState<string | null>(null);
    const [success, setSuccess] = useState(false);

    if (!isOpen) return null;

    const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        if (e.target.files && e.target.files[0]) {
            const file = e.target.files[0];
            setImageFile(file);
            const reader = new FileReader();
            reader.onloadend = () => {
                setImagePreview(reader.result as string);
            };
            reader.readAsDataURL(file);
        }
    };

    const handleSave = async (e: React.FormEvent) => {
        e.preventDefault();
        setSaving(true);
        setError(null);
        setSuccess(false);

        try {
            let imageUrl = currentConfig?.image_url || '';

            if (imageFile) {
                imageUrl = await ConfigService.uploadHeroImage(imageFile);
            }

            const newConfig: HeroConfig = {
                image_url: imageUrl,
                title: title
            };

            await ConfigService.updateHeroConfig(newConfig);
            onUpdate(newConfig);
            setSuccess(true);
            setTimeout(() => {
                onClose();
                setSuccess(false);
            }, 2000);
        } catch (err: any) {
            console.error(err);
            setError(err.message || "Error al guardar la configuració");
        } finally {
            setSaving(false);
        }
    };

    return (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm animate-in fade-in">
            <div className="bg-white dark:bg-slate-900 w-full max-w-lg rounded-3xl shadow-2xl overflow-hidden animate-in zoom-in-95 duration-200">
                <div className="flex items-center justify-between p-6 border-b border-slate-100 dark:border-slate-800">
                    <h2 className="text-xl font-bold text-slate-900 dark:text-white flex items-center gap-2">
                        Configuració del Hero
                    </h2>
                    <button onClick={onClose} className="p-2 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-full transition-colors text-slate-500">
                        <X size={20} />
                    </button>
                </div>

                <form onSubmit={handleSave} className="p-6 space-y-6">
                    <div className="space-y-4">
                        <label className="block text-sm font-bold text-slate-700 dark:text-slate-200">Preview i Canvi de Foto</label>
                        <div className="relative group rounded-2xl overflow-hidden aspect-[21/9] bg-slate-100 dark:bg-slate-800 border-2 border-dashed border-slate-200 dark:border-slate-700">
                            {imagePreview ? (
                                <img src={imagePreview} className="w-full h-full object-cover" alt="Hero preview" />
                            ) : (
                                <div className="flex flex-col items-center justify-center h-full text-slate-400">
                                    <Upload size={32} className="mb-2" />
                                    <span className="text-xs">Sense imatge</span>
                                </div>
                            )}
                            <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center">
                                <label className="bg-white text-slate-900 px-4 py-2 rounded-xl font-bold text-sm cursor-pointer shadow-lg hover:scale-105 transition-transform flex items-center gap-2">
                                    <Upload size={16} />
                                    Canviar Imatge
                                    <input type="file" className="hidden" accept="image/*" onChange={handleFileChange} />
                                </label>
                            </div>
                        </div>
                        <p className="text-[10px] text-slate-500 italic text-center">Recomanat: 1920x600px o similar format panoràmic.</p>
                    </div>

                    <div className="space-y-2">
                        <label className="block text-sm font-bold text-slate-700 dark:text-slate-200 text-left">Títol de Benvinguda</label>
                        <input
                            type="text"
                            value={title}
                            onChange={(e) => setTitle(e.target.value)}
                            className="w-full px-4 py-3 rounded-xl border border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-800 text-slate-900 dark:text-white outline-none focus:ring-2 focus:ring-primary transition-all font-medium"
                            placeholder="Ex: Benvinguts a l'AFA Falguera"
                        />
                    </div>

                    {error && (
                        <div className="p-3 bg-red-50 dark:bg-red-900/10 border border-red-100 dark:border-red-900/20 text-red-600 dark:text-red-400 rounded-xl flex items-center gap-2 text-sm animate-shake">
                            <AlertCircle size={16} />
                            <p>{error}</p>
                        </div>
                    )}

                    {success && (
                        <div className="p-3 bg-green-50 dark:bg-green-900/10 border border-green-100 dark:border-green-900/20 text-green-600 dark:text-green-400 rounded-xl flex items-center gap-2 text-sm animate-in fade-in slide-in-from-top-1">
                            <CheckCircle2 size={16} />
                            <p>Configuració guardada!</p>
                        </div>
                    )}

                    <div className="flex gap-3">
                        <button
                            type="button"
                            onClick={onClose}
                            className="flex-1 px-6 py-3 rounded-xl font-bold text-slate-600 dark:text-slate-400 border border-slate-200 dark:border-slate-700 hover:bg-slate-50 dark:hover:bg-slate-800 transition-colors"
                        >
                            Cancel·lar
                        </button>
                        <button
                            type="submit"
                            disabled={saving}
                            className="flex-[2] bg-primary hover:bg-primary/90 text-white font-bold px-6 py-3 rounded-xl shadow-lg shadow-primary/30 transition-all active:scale-95 disabled:opacity-50 flex items-center justify-center gap-2"
                        >
                            {saving ? (
                                <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin"></div>
                            ) : (
                                <>
                                    <Save size={18} />
                                    Guardar Canvis
                                </>
                            )}
                        </button>
                    </div>
                </form>
            </div>
        </div>
    );
}

import { motion, AnimatePresence } from 'framer-motion';
import { X, Users, Landmark } from 'lucide-react';
import { useTranslation } from 'react-i18next';
import { useEffect } from 'react';

import { useContentTranslation } from '../../hooks/useContentTranslation';

interface ProjectDetailModalProps {
  isOpen: boolean;
  onClose: () => void;
  project: {
    id: string;
    title: string;
    description: string;
    details?: string;
    imageAfter: string;
    impact?: string;
    participants?: string;
    budget?: number;
    status: 'completed' | 'in_progress' | 'voting' | 'active' | 'archived';
    translations?: any;
  } | null;
}

export const ProjectDetailModal = ({ isOpen, onClose, project }: ProjectDetailModalProps) => {
  const { t } = useTranslation();
  const { tContent } = useContentTranslation();

  // Prevent background scroll when modal is open
  useEffect(() => {
    if (isOpen) {
      document.body.style.overflow = 'hidden';
    } else {
      document.body.style.overflow = 'unset';
    }
    return () => {
      document.body.style.overflow = 'unset';
    };
  }, [isOpen]);

  if (!project) return null;

  // Function to render text with newlines (simple markdown-like)
  const renderDetails = (text?: string) => {
    if (!text) return null;
    return text.split('\n').map((line, index) => {
      const trimmedLine = line.trim();
      if (trimmedLine.startsWith('###')) {
        return <h3 key={index} className="text-xl font-bold text-slate-800 dark:text-white mt-6 mb-3">{trimmedLine.replace('###', '').trim()}</h3>;
      }
      if (trimmedLine.startsWith('**') && trimmedLine.endsWith('**')) {
        return <strong key={index} className="block mt-4 mb-2 text-slate-900 dark:text-white">{trimmedLine.replace(/\*\*/g, '')}</strong>;
      }
      if (trimmedLine.startsWith('- ')) {
        return <li key={index} className="ml-4 mb-1 text-slate-600 dark:text-slate-300 list-disc">{trimmedLine.replace('- ', '')}</li>;
      }
      return <p key={index} className="mb-4 text-slate-600 dark:text-slate-300 leading-relaxed">{line}</p>;
    });
  };

  return (
    <AnimatePresence>
      {isOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-0 sm:p-6">
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            onClick={onClose}
            className="absolute inset-0 bg-black/60 backdrop-blur-sm"
          />

          <motion.div
            initial={{ opacity: 0, scale: 0.95, y: 20 }}
            animate={{ opacity: 1, scale: 1, y: 0 }}
            exit={{ opacity: 0, scale: 0.95, y: 20 }}
            className="relative w-full h-full sm:h-auto max-w-4xl sm:max-h-[90vh] bg-white dark:bg-slate-900 sm:rounded-2xl shadow-2xl overflow-hidden flex flex-col"
          >
            <div className="relative h-64 sm:h-80 shrink-0">
              <img
                src={project.imageAfter}
                alt={project.title}
                className="w-full h-full object-cover"
              />
              <div className="absolute inset-0 bg-gradient-to-t from-black/80 to-transparent" />
              <button
                onClick={onClose}
                className="absolute top-4 right-4 p-2 bg-black/20 hover:bg-black/40 text-white rounded-full backdrop-blur-md transition-colors"
              >
                <X size={24} />
              </button>

              <div className="absolute bottom-0 left-0 right-0 p-6 sm:p-8">
                <span className={`inline-block px-3 py-1 mb-3 text-xs font-bold rounded-full uppercase tracking-wider ${project.status === 'completed' ? 'bg-green-500 text-white' :
                  project.status === 'voting' ? 'bg-amber-500 text-white' : 'bg-blue-500 text-white'
                  }`}>
                  {(() => {
                    const statusMap: Record<string, string> = {
                      'completed': 'featured_projects.status.completed',
                      'in_progress': 'featured_projects.status.in_progress',
                      'voting': 'featured_projects.status.voting',
                      'active': 'admin.projects.status_active',
                      'archived': 'admin.projects.status_archived'
                    };
                    return t(statusMap[project.status] as any || 'admin.projects.status_active');
                  })()}
                </span>
                <h2 className="text-3xl sm:text-4xl font-bold text-white mb-2">{tContent(project, 'title')}</h2>
                <p className="text-white/90 text-lg sm:text-xl max-w-2xl line-clamp-2">{tContent(project, 'description')}</p>
              </div>
            </div>

            <div className="flex-1 overflow-y-auto p-6 sm:p-8">
              <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
                <div className="lg:col-span-2 space-y-6">
                  {(project.details || (project.translations && tContent(project, 'details'))) ? (
                    <div className="prose dark:prose-invert max-w-none">
                      {renderDetails(tContent(project, 'details'))}
                    </div>
                  ) : (
                    <div className="text-slate-500 italic">No details available.</div>
                  )}
                </div>

                <div className="space-y-6">
                  <div className="bg-slate-50 dark:bg-slate-800 rounded-xl p-6 border border-slate-100 dark:border-slate-700">
                    <h4 className="text-sm font-bold uppercase text-slate-400 mb-4 tracking-wider">{t('featured_projects.details_title')}</h4>

                    <div className="space-y-4">
                      {project.impact && (
                        <div className="flex items-start gap-3">
                          <div className="p-2 bg-green-100 dark:bg-green-900/30 text-green-600 dark:text-green-400 rounded-lg shrink-0">
                            <Landmark size={18} />
                          </div>
                          <div>
                            <p className="text-xs text-slate-500 uppercase font-medium mb-0.5">{t('admin.projects.field_impact')}</p>
                            <p className="text-slate-800 dark:text-slate-200 font-medium">{project.impact}</p>
                          </div>
                        </div>
                      )}

                      {project.participants && (
                        <div className="flex items-start gap-3">
                          <div className="p-2 bg-blue-100 dark:bg-blue-900/30 text-blue-600 dark:text-blue-400 rounded-lg shrink-0">
                            <Users size={18} />
                          </div>
                          <div>
                            <p className="text-xs text-slate-500 uppercase font-medium mb-0.5">{t('admin.projects.field_participants')}</p>
                            <p className="text-slate-800 dark:text-slate-200 font-medium">{project.participants}</p>
                          </div>
                        </div>
                      )}

                      {project.budget && project.budget > 0 && (
                        <div className="flex items-start gap-3">
                          <div className="p-2 bg-amber-100 dark:bg-amber-900/30 text-amber-600 dark:text-amber-400 rounded-lg shrink-0">
                            <span className="font-bold text-sm">€</span>
                          </div>
                          <div>
                            <p className="text-xs text-slate-500 uppercase font-medium mb-0.5">{t('featured_projects.investment_label')}</p>
                            <p className="text-slate-800 dark:text-slate-200 font-medium">
                              {new Intl.NumberFormat('es-ES', { style: 'currency', currency: 'EUR' }).format(project.budget)}
                            </p>
                          </div>
                        </div>
                      )}
                    </div>
                  </div>


                </div>
              </div>
            </div>

            <div className="p-4 border-t border-slate-100 dark:border-slate-700 flex justify-end">
              <button
                onClick={onClose}
                className="px-6 py-2 bg-slate-100 hover:bg-slate-200 dark:bg-slate-800 dark:hover:bg-slate-700 text-slate-700 dark:text-slate-300 font-medium rounded-lg transition-colors"
              >
                {t('common.close') || 'Cerrar'}
              </button>
            </div>
          </motion.div>
        </div>
      )}
    </AnimatePresence>
  );
};

import { format } from 'date-fns';
import { Calendar as CalendarIcon, Clock, MapPin, ExternalLink, ChevronRight } from 'lucide-react';
import { Link } from 'react-router-dom';
import { useTranslation } from 'react-i18next';
import type { CalendarEvent } from '../../../services/CalendarService';

interface CalendarAgendaViewProps {
    agendaDates: Date[];
    getEventsForDay: (day: Date) => CalendarEvent[];
    isToday: (day: Date) => boolean;
    onEventClick: (event: CalendarEvent) => void;
    locale: any;
}

export function CalendarAgendaView({
    agendaDates,
    getEventsForDay,
    isToday,
    onEventClick,
    locale
}: CalendarAgendaViewProps) {
    const { t } = useTranslation();

    return (
        <div className="p-4 md:p-8 space-y-8 animate-in slide-in-from-bottom-5 duration-500">
            {agendaDates.length === 0 ? (
                <div className="flex flex-col items-center justify-center py-20 text-center space-y-4">
                    <div className="w-16 h-16 bg-slate-100 dark:bg-slate-800 rounded-3xl flex items-center justify-center text-slate-300">
                        <CalendarIcon size={32} />
                    </div>
                    <p className="text-slate-400 font-bold uppercase tracking-widest text-xs italic">
                        {t('calendar.no_events_month')}
                    </p>
                </div>
            ) : (
                agendaDates.map((day, dIdx) => {
                    const dayEvents = getEventsForDay(day);
                    const dayIsToday = isToday(day);

                    return (
                        <div key={dIdx} className="space-y-4">
                            <h2 className="text-[11px] font-bold uppercase tracking-[0.2em] text-slate-400 dark:text-slate-500 flex items-center gap-2">
                                {format(day, 'EEEE d MMMM', { locale })}
                                {dayIsToday && <span className="w-1.5 h-1.5 rounded-full bg-primary/40"></span>}
                            </h2>

                            <div className="space-y-3">
                                {dayEvents.map((event, eIdx) => (
                                    <div
                                        key={eIdx}
                                        className="group relative flex items-center py-6 border-b border-slate-50 dark:border-slate-800/50 last:border-0 transition-all active:scale-[0.98]"
                                    >
                                        <div
                                            className="absolute left-0 top-6 bottom-6 w-1 rounded-full opacity-60"
                                            style={{ backgroundColor: event.color }}
                                        />

                                        <div className="flex-1 pl-6">
                                            <div className="flex items-center gap-3 text-[11px] font-bold text-slate-400 uppercase tracking-[0.15em] mb-1.5">
                                                {(!event.all_day && event.start_time) ? (
                                                    <div className="flex items-center gap-1.5 text-primary/80">
                                                        <Clock size={12} strokeWidth={3} />
                                                        <span>{event.start_time}</span>
                                                    </div>
                                                ) : (
                                                    <span className="text-primary/70">{t('common.all_day', 'Tot el dia')}</span>
                                                )}
                                                {event.location && (
                                                    <span className="opacity-30">|</span>
                                                )}
                                                {event.location && (
                                                    <div className="flex items-center gap-1.5 text-slate-500 dark:text-slate-400">
                                                        <MapPin size={12} strokeWidth={3} />
                                                        <span className="truncate max-w-[150px]">{event.location}</span>
                                                    </div>
                                                )}
                                            </div>

                                            <h3 className="text-sm font-bold text-slate-800 dark:text-white leading-tight group-hover:text-primary transition-colors">
                                                {event.title}
                                            </h3>
                                        </div>

                                        <div className="flex items-center gap-2">
                                            {event.link ? (
                                                <Link
                                                    to={event.link}
                                                    className="p-3 bg-primary/5 text-primary rounded-2xl hover:bg-primary hover:text-white transition-all shadow-sm"
                                                >
                                                    <ExternalLink size={14} />
                                                </Link>
                                            ) : (
                                                <button
                                                    onClick={() => onEventClick(event)}
                                                    className="p-2.5 bg-slate-50 dark:bg-slate-800 text-slate-400 rounded-2xl hover:bg-primary/10 hover:text-primary transition-all"
                                                >
                                                    <ChevronRight size={16} />
                                                </button>
                                            )}
                                        </div>
                                    </div>
                                ))}
                            </div>
                        </div>
                    );
                })
            )}
        </div>
    );
}

