  const [additionalInfo, setAdditionalInfo] = useState<AdditionalInfo>({
    healthInfo: '', imageRights: 'si', canLeaveAlone: 'false', authorizedPickup: '', termsAccepted: false
  });

  // Handlers
  const addStudent = () => {
    if (students.length < 3) {
      setStudents([...students, { name: '', surname: '', course: '', activities: [] }]);
    }
  };

  const removeStudent = (index: number) => {
    const newStudents = [...students];
    newStudents.splice(index, 1);
    setStudents(newStudents);
  };

  const updateStudent = (index: number, field: keyof Student, value: string | string[]) => {
    const newStudents = [...students];
    newStudents[index] = { ...newStudents[index], [field]: value };

    if (field === 'course') {
      newStudents[index].activities = [];
    }
    setStudents(newStudents);
  };

  const toggleActivity = (studentIndex: number, activityValue: string) => {
    const newStudents = [...students];
    const activities = newStudents[studentIndex].activities;
    if (activities.includes(activityValue)) {
      newStudents[studentIndex].activities = activities.filter(a => a !== activityValue);
    } else {
      newStudents[studentIndex].activities = [...activities, activityValue];
    }
    setStudents(newStudents);
  };

  const getAvailableActivities = (courseCode: string) => {
    const course = COURSES.find(c => c.value === courseCode);
    if (!course) return [];
    // @ts-ignore
    return ALL_ACTIVITIES[course.type] || [];
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError(null);

    if (!additionalInfo.termsAccepted) {
      setError(t('inscription.form.error_terms'));
      setLoading(false);
      return;
    }

    if (students.some(s => s.activities.length === 0)) {
      setError(t('inscription.form.error_activities'));
      setLoading(false);
      return;
    }

    try {
      const payload = {
        parent_name: parentInfo.name,
        parent_dni: parentInfo.dni,
        parent_phone_1: parentInfo.phone1,
        parent_phone_2: parentInfo.phone2 || null,
        parent_email_1: parentInfo.email1,
        parent_email_2: parentInfo.email2 || null,
        afa_member: parentInfo.isAfaMember === 'true',
        students: students.map(s => ({
          name: s.name,
          surname: s.surname,
          course: s.course,
          activities: s.activities
        })),
        health_info: additionalInfo.healthInfo || null,
        image_auth_consent: additionalInfo.imageRights,
        can_leave_alone: additionalInfo.canLeaveAlone === 'true',
        authorized_pickup: additionalInfo.authorizedPickup || null,
        conditions_accepted: true,
        form_language: i18n.language,
        status: 'alta'
      };

      const { error: insertError } = await supabase
        .from('inscripcions')
        .insert([payload]);

      if (insertError) throw insertError;

      setSubmitted(true);
      window.scrollTo(0, 0);

    } catch (err) {
      console.error(err);
      const errorMessage = err instanceof Error ? err.message : String(err);
      setError(errorMessage || t('inscription.form.error_generic'));
    } finally {
      setLoading(false);
    }
  };

  if (submitted) {
    return (
      <div className="container mx-auto px-4 py-12 max-w-2xl text-center">
        <div className="bg-green-50 border border-green-200 rounded-lg p-6 shadow-sm">
          <div className="rounded-full bg-green-100 p-3 w-16 h-16 mx-auto mb-4 flex items-center justify-center">
            <CheckCircle2 className="w-8 h-8 text-green-600" />
          </div>
          <h2 className="text-2xl font-bold text-green-800 mb-2">{t('inscription.form.success_title')}</h2>
          <p className="text-green-700 mb-6">
            {t('inscription.form.success_message')}
          </p>
          <button
            onClick={() => navigate('/')}
            className="bg-green-600 hover:bg-green-700 text-white font-medium py-2 px-6 rounded-md transition-colors"
          >
            {t('inscription.form.back_home')}
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="container mx-auto px-4 py-8 max-w-4xl">
      <div className="text-center mb-12">
        <motion.div
          initial={{ opacity: 0, y: -20 }}
          animate={{ opacity: 1, y: 0 }}
          className="inline-flex items-center justify-center p-3 rounded-full bg-blue-100/50 text-blue-600 mb-6 ring-4 ring-blue-50"
        >
          <Rocket className="w-8 h-8" />
        </motion.div>
        <h1 className="text-4xl md:text-5xl font-extrabold text-slate-900 mb-4 tracking-tight">
          {t('inscription.title_prefix')} <br className="hidden md:block" />
          <span className="bg-clip-text text-transparent bg-gradient-to-r from-blue-600 to-indigo-600">
            {t('inscription.title_highlight')}
          </span>
        </h1>
        <p className="text-lg text-slate-600 max-w-2xl mx-auto leading-relaxed">
          {t('inscription.subtitle_prefix')} <span className="text-blue-600 font-semibold bg-blue-50 px-2 py-0.5 rounded">{t('inscription.subtitle_highlight')}</span> {t('inscription.subtitle_suffix')}
        </p>
      </div>

      <div className="bg-white border border-slate-200 p-6 mb-10 rounded-2xl flex gap-5 items-start shadow-sm ring-1 ring-slate-100">
        <div className="bg-blue-100 p-2 rounded-lg shrink-0">
          <Info className="w-6 h-6 text-blue-600" />
        </div>
        <div>
          <h3 className="font-bold text-slate-900 text-lg mb-1">{t('inscription.info_box.title')}</h3>
          <p className="text-slate-600 leading-relaxed">
            {t('inscription.info_box.text')}
          </p>
        </div>
      </div>

      {/* --- Pricing & Payment Section --- */}
      <section className="mb-10 space-y-6">
        <h2 className="text-xl font-bold bg-slate-100 px-4 py-2 rounded-lg border-l-4 border-blue-500 text-slate-800">
          {t('inscription.pricing.title')}
        </h2>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
          <div className="bg-white border border-slate-200 p-5 rounded-xl shadow-sm hover:shadow-md transition-shadow">
            <h4 className="font-bold text-slate-900 mb-1">{t('inscription.pricing.general_title')}</h4>
            <p className="text-xs text-slate-500 mb-3">{t('inscription.pricing.hours_general')}</p>
            <div className="space-y-1">
              <p><span className="font-bold text-blue-600">20€</span> <span className="text-sm text-slate-600">{t('inscription.pricing.socis')}</span></p>
              <p><span className="font-bold text-slate-400">25€</span> <span className="text-sm text-slate-600">{t('inscription.pricing.no_socis')}</span></p>
            </div>
          </div>

          <div className="bg-indigo-50 border border-indigo-100 p-5 rounded-xl shadow-sm hover:shadow-md transition-shadow relative overflow-hidden">

            <div className="absolute top-0 right-0 bg-indigo-500 text-white text-[10px] px-2 py-0.5 rounded-bl-lg font-bold">INFO</div>
            <h4 className="font-bold text-indigo-900 mb-1">{t('inscription.pricing.english_title')}</h4>
            <p className="text-xs text-indigo-500 mb-3">{t('inscription.pricing.hours_general')}</p>
            <div className="space-y-1">
              <p><span className="font-bold text-indigo-600">39€</span> <span className="text-sm text-indigo-700">{t('inscription.pricing.socis')}</span></p>
              <p><span className="font-bold text-indigo-400">44€</span> <span className="text-sm text-indigo-700">{t('inscription.pricing.no_socis')}</span></p>
            </div>
            <div className="mt-3 text-[10px] bg-indigo-100/50 p-2 rounded border border-indigo-200 text-indigo-700">
              {t('inscription.pricing.english_material')}
            </div>
          </div>
        </div>

        <div className="bg-slate-50 p-4 rounded-xl border border-slate-200 text-sm text-slate-600">
          <p><strong>{t('inscription.pricing.discount_title')}</strong> {t('inscription.pricing.discount_body')}</p>
        </div>

        <div className="bg-red-50 p-4 rounded-xl border border-red-100 flex gap-4 items-start shadow-sm">
          <AlertCircle className="w-5 h-5 text-red-500 shrink-0 mt-0.5" />
          <div className="text-sm">
            <p className="font-bold text-red-800 mb-1">{t('inscription.pricing.english_warning_title')}</p>
            <p className="text-red-700 leading-relaxed italic">{t('inscription.pricing.english_warning_body')}</p>
          </div>
        </div>

        {/* Payment Info Box */}
        <div className="bg-emerald-50 border border-emerald-100 p-6 rounded-2xl shadow-sm">
          <h4 className="font-bold text-emerald-900 mb-4 flex items-center gap-2">
            <CreditCard className="w-5 h-5 text-emerald-600" />
            {t('inscription.pricing.payment_method_title')}
          </h4>
          <p className="text-sm text-emerald-800 mb-4">{t('inscription.pricing.payment_method_body')}</p>

          <div className="flex flex-col sm:flex-row items-center gap-3 bg-white p-3 rounded-xl border border-emerald-200/50">
            <code className="text-sm font-mono text-slate-700 bg-slate-50 px-3 py-1.5 rounded-lg flex-grow block w-full text-center sm:text-left">
              ES22 0081 1604 7400 0103 8208
            </code>
            <button
              onClick={(e) => {
                e.preventDefault();
                navigator.clipboard.writeText('ES22 0081 1604 7400 0103 8208');
                // Could add a toast here
              }}
              className="bg-emerald-600 hover:bg-emerald-700 text-white text-xs font-bold py-2.5 px-4 rounded-lg transition-colors shadow-sm shrink-0 w-full sm:w-auto"
            >
              {t('inscription.pricing.copy_iban')}
            </button>
          </div>
          <p className="text-[10px] text-emerald-600 font-bold mt-3 text-center sm:text-left uppercase tracking-tight">
            {t('inscription.pricing.iban_hint')}
          </p>
        </div>
      </section>

      {error && (
        <div className="bg-red-50 text-red-800 border-l-4 border-red-500 p-4 mb-6 rounded-r-lg flex items-center gap-2">
          <AlertCircle className="h-5 w-5" />
          <span>{error}</span>
        </div>
      )}

      <form onSubmit={handleSubmit} className="space-y-8">

        {/* --- Students Section --- */}
        <section className="space-y-6">
          <h2 className="text-xl font-semibold border-b pb-2">{t('inscription.form.student_section')}</h2>

          {students.map((student, index) => {
            const activities = student.course ? getAvailableActivities(student.course) : [];
            return (
              <div key={index} className="bg-white border rounded-lg shadow-sm overflow-hidden">
                <div className="bg-gray-50 px-4 py-3 border-b flex justify-between items-center">
                  <h3 className="font-medium text-gray-700">{t('inscription.form.student_label')} {index + 1}</h3>
                  {index > 0 && <button type="button" className="text-red-500 hover:text-red-700 text-sm font-medium" onClick={() => removeStudent(index)}>{t('inscription.form.remove_student')}</button>}
                </div>
                <div className="p-6 space-y-6">
                  <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                    <div className="space-y-2">
                      <label className="block text-sm font-medium text-gray-700">{t('inscription.form.name')} <span className="text-red-500">*</span></label>
                      <input
                        className="flex h-10 w-full rounded-md border border-slate-300 bg-white px-3 py-2 text-sm placeholder:text-slate-400 focus:outline-none focus:ring-2 focus:ring-blue-500 disabled:cursor-not-allowed disabled:opacity-50"
                        value={student.name}
                        onChange={(e) => updateStudent(index, 'name', e.target.value)}
                        required
                        placeholder={t('inscription.form.name')}
                      />
                    </div>
                    <div className="space-y-2">
                      <label className="block text-sm font-medium text-gray-700">{t('inscription.form.surname')} <span className="text-red-500">*</span></label>
                      <input
                        className="flex h-10 w-full rounded-md border border-slate-300 bg-white px-3 py-2 text-sm placeholder:text-slate-400 focus:outline-none focus:ring-2 focus:ring-blue-500"
                        value={student.surname}
                        onChange={(e) => updateStudent(index, 'surname', e.target.value)}
                        required
                        placeholder={t('inscription.form.surname')}
                      />
                    </div>
                    <div className="space-y-2">
                      <label className="block text-sm font-medium text-gray-700">{t('inscription.form.course')} <span className="text-red-500">*</span></label>
                      <select
                        className="flex h-10 w-full rounded-md border border-slate-300 bg-white px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-blue-500"
                        value={student.course}
                        onChange={(e) => updateStudent(index, 'course', e.target.value)}
                        required
                      >
                        <option value="" disabled>{t('inscription.form.select_course')}</option>
                        {COURSES.map(c => <option key={c.value} value={c.value}>{c.label}</option>)}
                      </select>
                    </div>
                  </div>

                  {/* Activities Selection */}
                  {student.course && (
                    <div className="bg-blue-50/50 p-4 rounded-lg border border-blue-100">
                      <h4 className="text-sm font-semibold text-blue-900 mb-3 uppercase tracking-wide">
                        {t('inscription.form.available_activities')} {COURSES.find(c => c.value === student.course)?.label}
                      </h4>
                      {activities.length === 0 ? (
                        <p className="text-sm text-gray-500">{t('inscription.form.no_activities')}</p>
                      ) : (
                        <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                          {activities.map((act: { value: string; label: string }) => (
                            <div
                              key={act.value}
                              className={`
                                            flex items-start space-x-3 p-3 rounded-md border cursor-pointer transition-all
                                            ${student.activities.includes(act.value)
                                  ? 'border-blue-500 bg-blue-50 ring-1 ring-blue-500'
                                  : 'border-gray-200 bg-white hover:border-blue-300'
                                }
                                        `}
                              onClick={() => toggleActivity(index, act.value)}
                            >
                              <input
                                type="checkbox"
                                id={`act-${index}-${act.value}`}
                                checked={student.activities.includes(act.value)}
                                onChange={() => toggleActivity(index, act.value)}
                                className="mt-1 h-4 w-4 rounded border-gray-300 text-blue-600 focus:ring-blue-500"
                              />
                              <label
                                htmlFor={`act-${index}-${act.value}`}
                                className="text-sm font-medium leading-none cursor-pointer select-none"
                              >
                                {act.label}
                              </label>
                            </div>
                          ))}
                        </div>
                      )}
                      {student.activities.length === 0 && <p className="text-xs text-red-500 mt-2">{t('inscription.form.must_select_activity')}</p>}
                    </div>
                  )}
                </div>
              </div>
            );
          })}

          {students.length < 3 && (
            <button
              type="button"
              onClick={addStudent}
              className="w-full py-2 border-2 border-dashed border-gray-300 rounded-lg text-gray-600 hover:border-blue-500 hover:text-blue-600 transition-colors"
            >
              {t('inscription.form.add_student')}
            </button>
          )}
        </section>

        {/* --- Parent Section --- */}
        <section className="space-y-6">
          <h2 className="text-xl font-semibold border-b pb-2">{t('inscription.form.parent_section')}</h2>
          <div className="bg-white border rounded-lg shadow-sm p-6">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="space-y-2">
                <label className="block text-sm font-medium text-gray-700">{t('inscription.form.name')} <span className="text-red-500">*</span></label>
                <input className="flex h-10 w-full rounded-md border border-slate-300 px-3 py-2 text-sm focus:ring-2 focus:ring-blue-500" value={parentInfo.name} onChange={e => setParentInfo({ ...parentInfo, name: e.target.value })} required />
              </div>
              <div className="space-y-2">
                <label className="block text-sm font-medium text-gray-700">{t('inscription.form.dni')} <span className="text-red-500">*</span></label>
                <input className="flex h-10 w-full rounded-md border border-slate-300 px-3 py-2 text-sm focus:ring-2 focus:ring-blue-500" value={parentInfo.dni} onChange={e => setParentInfo({ ...parentInfo, dni: e.target.value })} required />
              </div>
              <div className="space-y-2">
                <label className="block text-sm font-medium text-gray-700">{t('inscription.form.phone_1')} <span className="text-red-500">*</span></label>
                <input type="tel" className="flex h-10 w-full rounded-md border border-slate-300 px-3 py-2 text-sm focus:ring-2 focus:ring-blue-500" value={parentInfo.phone1} onChange={e => setParentInfo({ ...parentInfo, phone1: e.target.value })} required />
              </div>
              <div className="space-y-2">
                <label className="block text-sm font-medium text-gray-700">{t('inscription.form.phone_2')}</label>
                <input type="tel" className="flex h-10 w-full rounded-md border border-slate-300 px-3 py-2 text-sm focus:ring-2 focus:ring-blue-500" value={parentInfo.phone2} onChange={e => setParentInfo({ ...parentInfo, phone2: e.target.value })} />
              </div>
              <div className="space-y-2">
                <label className="block text-sm font-medium text-gray-700">{t('inscription.form.email_1')} <span className="text-red-500">*</span></label>
                <input type="email" className="flex h-10 w-full rounded-md border border-slate-300 px-3 py-2 text-sm focus:ring-2 focus:ring-blue-500" value={parentInfo.email1} onChange={e => setParentInfo({ ...parentInfo, email1: e.target.value })} required />
              </div>
              <div className="space-y-2">
                <label className="block text-sm font-medium text-gray-700">{t('inscription.form.email_2')}</label>
                <input type="email" className="flex h-10 w-full rounded-md border border-slate-300 px-3 py-2 text-sm focus:ring-2 focus:ring-blue-500" value={parentInfo.email2} onChange={e => setParentInfo({ ...parentInfo, email2: e.target.value })} />
              </div>
              <div className="md:col-span-2 space-y-3">
                <label className="block text-sm font-medium text-gray-700">{t('inscription.form.is_member')} <span className="text-red-500">*</span></label>
                <div className="flex space-x-6">
                  <label className="flex items-center space-x-2 cursor-pointer">
                    <input type="radio" name="afa_member" value="true" checked={parentInfo.isAfaMember === 'true'} onChange={() => setParentInfo({ ...parentInfo, isAfaMember: 'true' })} className="h-4 w-4 text-blue-600 focus:ring-blue-500" />
                    <span>{t('inscription.form.yes')}</span>
                  </label>
                  <label className="flex items-center space-x-2 cursor-pointer">
                    <input type="radio" name="afa_member" value="false" checked={parentInfo.isAfaMember === 'false'} onChange={() => setParentInfo({ ...parentInfo, isAfaMember: 'false' })} className="h-4 w-4 text-blue-600 focus:ring-blue-500" />
                    <span>{t('inscription.form.no')}</span>
                  </label>
                </div>
              </div>
            </div>
          </div>
        </section>

        {/* --- Additional Info Section --- */}
        <section className="space-y-6">
          <h2 className="text-xl font-semibold border-b pb-2">{t('inscription.form.additional_section')}</h2>
          <div className="bg-white border rounded-lg shadow-sm p-6 space-y-6">
            <div className="space-y-2">
              <label className="block text-sm font-medium text-gray-700">{t('inscription.form.health_info')}</label>
              <input
                className="flex h-10 w-full rounded-md border border-slate-300 px-3 py-2 text-sm focus:ring-2 focus:ring-blue-500"
                value={additionalInfo.healthInfo}
                onChange={e => setAdditionalInfo({ ...additionalInfo, healthInfo: e.target.value })}
                placeholder={t('inscription.form.health_placeholder')}
              />
            </div>

            <div className="space-y-3">
              <label className="block text-sm font-medium text-gray-700">{t('inscription.form.image_rights')} <span className="text-red-500">*</span></label>
              <p className="text-xs text-gray-500">
                {t('inscription.form.image_text')}
              </p>
              <div className="flex flex-col space-y-2">
                <label className="flex items-center space-x-2 cursor-pointer">
                  <input type="radio" name="img_rights" value="si" checked={additionalInfo.imageRights === 'si'} onChange={() => setAdditionalInfo({ ...additionalInfo, imageRights: 'si' })} className="h-4 w-4 text-blue-600 focus:ring-blue-500" />
                  <span>{t('inscription.form.image_yes')}</span>
                </label>
                <label className="flex items-center space-x-2 cursor-pointer">
                  <input type="radio" name="img_rights" value="no" checked={additionalInfo.imageRights === 'no'} onChange={() => setAdditionalInfo({ ...additionalInfo, imageRights: 'no' })} className="h-4 w-4 text-blue-600 focus:ring-blue-500" />
                  <span>{t('inscription.form.image_no')}</span>
                </label>
              </div>
            </div>

            <div className="space-y-3">
              <label className="block text-sm font-medium text-gray-700">{t('inscription.form.leave_alone')} <span className="text-red-500">*</span></label>
              <p className="text-xs text-gray-500">{t('inscription.form.leave_alone_text')}</p>
              <div className="flex space-x-6">
                <label className="flex items-center space-x-2 cursor-pointer">
                  <input type="radio" name="leave_alone" value="true" checked={additionalInfo.canLeaveAlone === 'true'} onChange={() => setAdditionalInfo({ ...additionalInfo, canLeaveAlone: 'true' })} className="h-4 w-4 text-blue-600 focus:ring-blue-500" />
                  <span>{t('inscription.form.yes')}</span>
                </label>
                <label className="flex items-center space-x-2 cursor-pointer">
                  <input type="radio" name="leave_alone" value="false" checked={additionalInfo.canLeaveAlone === 'false'} onChange={() => setAdditionalInfo({ ...additionalInfo, canLeaveAlone: 'false' })} className="h-4 w-4 text-blue-600 focus:ring-blue-500" />
                  <span>{t('inscription.form.no')}</span>
                </label>
              </div>
            </div>

            {additionalInfo.canLeaveAlone === 'false' && (
              <div className="space-y-2">
                <label className="block text-sm font-medium text-gray-700">{t('inscription.form.authorized_pickup')}</label>
                <textarea
                  className="flex min-h-[80px] w-full rounded-md border border-slate-300 px-3 py-2 text-sm focus:ring-2 focus:ring-blue-500"
                  placeholder={t('inscription.form.authorized_pickup_placeholder')}
                  value={additionalInfo.authorizedPickup}
                  onChange={e => setAdditionalInfo({ ...additionalInfo, authorizedPickup: e.target.value })}
                />
              </div>
            )}

            <div className="pt-4 border-t">
              <div className="flex items-center space-x-2">
                <input
                  type="checkbox"
                  id="terms"
                  checked={additionalInfo.termsAccepted}
                  onChange={(e) => setAdditionalInfo({ ...additionalInfo, termsAccepted: e.target.checked })}
                  className="h-4 w-4 rounded border-gray-300 text-blue-600 focus:ring-blue-500"
                />
                <label htmlFor="terms" className="text-sm text-gray-700 cursor-pointer select-none">
                  {t('inscription.form.terms_accept')} <a href="#" className="text-blue-600 underline hover:text-blue-800">{t('inscription.form.terms_link')}</a>. <span className="text-red-500">*</span>
                </label>
              </div>
            </div>
          </div>
        </section>

        <div className="pt-6">
          <button
            type="submit"
            className="w-full bg-blue-600 hover:bg-blue-700 text-white text-lg font-semibold py-4 rounded-lg shadow-md hover:shadow-lg transition-all flex justify-center items-center disabled:opacity-70 disabled:cursor-not-allowed"
            disabled={loading}
          >
            {loading ? <Loader2 className="mr-2 h-5 w-5 animate-spin" /> : t('inscription.form.submit_btn')}
          </button>
          <p className="text-center text-xs text-gray-500 mt-4">
            {t('inscription.form.privacy_note')}
          </p>
        </div>

      </form>
    </div>
  );
}

import { useEffect, useState } from 'react';
import { useTranslation } from 'react-i18next';
import { Newspaper } from 'lucide-react';
import { PublicNewsService, type NewsArticle } from '../services/PublicNewsService';
import { NewsListHeader } from '../components/public/news/NewsListHeader';
import { NewsCard } from '../components/public/news/NewsCard';

export function NewsPage() {
  const { t, i18n } = useTranslation();
  const [news, setNews] = useState<NewsArticle[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchNews();
    window.scrollTo(0, 0);
  }, [i18n.language]);

  const fetchNews = async () => {
    setLoading(true);
    try {
      const data = await PublicNewsService.getAllNews(i18n.language);
      setNews(data);
    } catch (error) {
      console.error('Error fetching news:', error);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 dark:bg-slate-900 pt-24 pb-12">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <NewsListHeader />

        {/* Loading State */}
        {loading ? (
          <div className="flex flex-col items-center justify-center py-20">
            <div className="w-12 h-12 border-4 border-primary border-t-transparent rounded-full animate-spin mb-4" />
            <p className="text-slate-500 font-medium">{t('common.loading')}</p>
          </div>
        ) : news.length === 0 ? (
          <div className="text-center py-20 bg-white dark:bg-slate-800 rounded-3xl border-2 border-dashed border-slate-200 dark:border-slate-700">
            <Newspaper className="w-16 h-16 text-slate-300 dark:text-slate-600 mx-auto mb-4" />
            <p className="text-xl font-bold text-slate-400">
              {t('admin.news.no_articles')}
            </p>
          </div>
        ) : (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8 text-left">
            {news.map((article) => (
              <NewsCard key={article.id} article={article} />
            ))}
          </div>
        )}
      </div>
    </div>
  );
}

import { useState, useEffect } from 'react';
import { supabase } from '../../lib/supabase';
import { useTranslation } from 'react-i18next';
import { Save, AlertCircle, Plus, Trash2, Clock } from 'lucide-react';

interface AcollidaRate {
    id?: string;
    horari: string;
    preu_soci_mes: string;
    preu_soci_ocasional: string | null;
    preu_no_soci_mes: string;
    preu_no_soci_ocasional: string | null;
    order_index: number;
}

export default function AcollidaManager() {
    const { t } = useTranslation();
    const [rates, setRates] = useState<AcollidaRate[]>([]);
    const [loading, setLoading] = useState(true);
    const [saving, setSaving] = useState(false);
    const [error, setError] = useState<string | null>(null);

    useEffect(() => {
        fetchRates();
    }, []);

    const fetchRates = async () => {
        try {
            const { data, error } = await supabase
                .from('acollida_rates')
                .select('*')
                .order('order_index', { ascending: true });

            if (error) throw error;
            setRates(data || []);
        } catch (err: any) {
            console.error(err);
            setError('Error al cargar las tarifas');
        } finally {
            setLoading(false);
        }
    };

    const handleAddRate = () => {
        const newRate: AcollidaRate = {
            horari: '',
            preu_soci_mes: '',
            preu_soci_ocasional: '',
            preu_no_soci_mes: '',
            preu_no_soci_ocasional: '',
            order_index: rates.length + 1
        };
        setRates([...rates, newRate]);
    };

    const handleRemoveRate = (index: number) => {
        setRates(rates.filter((_, i) => i !== index));
    };

    const handleChange = (index: number, field: keyof AcollidaRate, value: string) => {
        const newRates = [...rates];
        newRates[index] = { ...newRates[index], [field]: value };
        setRates(newRates);
    };

    const handleSave = async () => {
        setSaving(true);
        setError(null);
        try {
            // First, delete existing to replace with the current list
            const { error: delError } = await supabase
                .from('acollida_rates')
                .delete()
                .neq('horari', 'FORCE_DELETE_ALL'); // Simple way to delete all

            if (delError) throw delError;

            // Then insert new ones
            const { error: insError } = await supabase
                .from('acollida_rates')
                .insert(rates.map((r, i) => ({
                    horari: r.horari,
                    preu_soci_mes: r.preu_soci_mes,
                    preu_soci_ocasional: r.preu_soci_ocasional,
                    preu_no_soci_mes: r.preu_no_soci_mes,
                    preu_no_soci_ocasional: r.preu_no_soci_ocasional,
                    order_index: i
                })));

            if (insError) throw insError;
            alert('Cambios guardados correctamente');
        } catch (err: any) {
            console.error(err);
            setError('Error al guardar. Verifica los permisos de la tabla.');
        } finally {
            setSaving(false);
        }
    };

    return (
        <div className="p-6 max-w-5xl mx-auto">
            <div className="flex justify-between items-center mb-8">
                <div>
                    <h1 className="text-3xl font-bold text-slate-800 dark:text-white">Gestión de Acogida</h1>
                    <p className="text-slate-500">Configura los horarios y precios del servicio de acogida.</p>
                </div>
                <button
                    onClick={handleSave}
                    disabled={saving}
                    className="bg-primary hover:bg-primary/90 text-white px-6 py-2.5 rounded-xl font-bold shadow-lg shadow-primary/30 flex items-center gap-2 transition-all disabled:opacity-50"
                >
                    {saving ? 'Guardando...' : <><Save className="w-5 h-5" /> Guardar Cambios</>}
                </button>
            </div>

            {error && (
                <div className="bg-red-50 text-red-800 p-4 rounded-xl mb-6 flex items-center gap-3 border border-red-200">
                    <AlertCircle className="w-5 h-5" />
                    {error}
                </div>
            )}

            {loading ? (
                <div className="flex items-center justify-center py-20">
                    <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-primary"></div>
                </div>
            ) : (
                <div className="bg-white dark:bg-slate-800 rounded-3xl border border-slate-200 dark:border-slate-700 overflow-hidden shadow-sm">
                    <div className="p-6">
                        <table className="w-full">
                            <thead>
                                <tr className="text-left text-xs font-bold text-slate-400 uppercase tracking-wider border-b border-slate-100 dark:border-slate-700">
                                    <th className="pb-4 px-2">Horario</th>
                                    <th className="pb-4 px-2">Socio (Mes/Oc.)</th>
                                    <th className="pb-4 px-2">No Socio (Mes/Oc.)</th>
                                    <th className="pb-4 px-2 w-10"></th>
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-slate-50 dark:divide-slate-800">
                                {rates.map((rate, index) => (
                                    <tr key={index} className="group">
                                        <td className="py-4 px-2">
                                            <div className="relative">
                                                <Clock className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 w-4 h-4" />
                                                <input
                                                    type="text"
                                                    value={rate.horari}
                                                    onChange={(e) => handleChange(index, 'horari', e.target.value)}
                                                    placeholder="Ej: 7:30H A 9H"
                                                    className="w-full pl-9 pr-4 py-2 bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-lg outline-none focus:ring-2 focus:ring-primary/20"
                                                />
                                            </div>
                                        </td>
                                        <td className="py-4 px-2">
                                            <div className="flex gap-2">
                                                <input
                                                    type="text"
                                                    value={rate.preu_soci_mes}
                                                    onChange={(e) => handleChange(index, 'preu_soci_mes', e.target.value)}
                                                    placeholder="Mes (64€)"
                                                    className="w-24 px-3 py-2 bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-lg outline-none focus:ring-2 focus:ring-primary/20"
                                                />
                                                <input
                                                    type="text"
                                                    value={rate.preu_soci_ocasional || ''}
                                                    onChange={(e) => handleChange(index, 'preu_soci_ocasional', e.target.value)}
                                                    placeholder="Oc. (10€)"
                                                    className="w-24 px-3 py-2 bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-lg outline-none focus:ring-2 focus:ring-primary/20"
                                                />
                                            </div>
                                        </td>
                                        <td className="py-4 px-2">
                                            <div className="flex gap-2">
                                                <input
                                                    type="text"
                                                    value={rate.preu_no_soci_mes}
                                                    onChange={(e) => handleChange(index, 'preu_no_soci_mes', e.target.value)}
                                                    placeholder="Mes (68€)"
                                                    className="w-24 px-3 py-2 bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-lg outline-none focus:ring-2 focus:ring-primary/20"
                                                />
                                                <input
                                                    type="text"
                                                    value={rate.preu_no_soci_ocasional || ''}
                                                    onChange={(e) => handleChange(index, 'preu_no_soci_ocasional', e.target.value)}
                                                    placeholder="Oc. (14€)"
                                                    className="w-24 px-3 py-2 bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-lg outline-none focus:ring-2 focus:ring-primary/20"
                                                />
                                            </div>
                                        </td>
                                        <td className="py-4 px-2">
                                            <button
                                                onClick={() => handleRemoveRate(index)}
                                                className="p-2 text-slate-300 hover:text-red-500 transition-colors opacity-0 group-hover:opacity-100"
                                            >
                                                <Trash2 size={18} />
                                            </button>
                                        </td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>

                        <button
                            onClick={handleAddRate}
                            className="mt-6 w-full py-4 border-2 border-dashed border-slate-200 dark:border-slate-700 rounded-2xl text-slate-400 font-bold hover:border-primary hover:text-primary transition-all flex items-center justify-center gap-2"
                        >
                            <Plus size={20} />
                            {t('admin.acollidaManager.addRate')}
                        </button>
                    </div>
                </div>
            )}

            <div className="mt-8 bg-blue-50 dark:bg-blue-900/10 p-6 rounded-3xl border border-blue-100 dark:border-blue-900/20">
                <h3 className="font-bold text-blue-800 dark:text-blue-200 mb-2 flex items-center gap-2">
                    <AlertCircle size={20} /> {t('admin.acollidaManager.adminNote.title')}
                </h3>
                <p className="text-sm text-blue-700 dark:text-blue-300 leading-relaxed">
                    {t('admin.acollidaManager.adminNote.description')}
                </p>
            </div>
        </div>
    );
}

import { useEffect, useState, useCallback } from "react";
import { ActivityService } from "../../services/ActivityService";
import { useTranslation } from "react-i18next";
import type { Activity } from "../../services/ActivityService";
import { ActivityEditorModal } from "../../components/admin/ActivityEditorModal";
import { AlertCircle } from "lucide-react";
import { ActivityAdminHeader } from "../../components/admin/activities/ActivityAdminHeader";
import { ActivityAdminCard } from "../../components/admin/activities/ActivityAdminCard";

export default function ActivitiesManager() {
  const { t } = useTranslation();
  const [activities, setActivities] = useState<Activity[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  // Editor State
  const [isEditorOpen, setIsEditorOpen] = useState(false);
  const [editingActivity, setEditingActivity] = useState<Activity | null>(null);

  const fetchActivities = useCallback(async () => {
    setLoading(true);
    setError(null);
    try {
      const data = await ActivityService.getAll();
      setActivities(data);
    } catch (err: any) {
      console.error(err);
      setError(t('admin.activities.error_load'));
    } finally {
      setLoading(false);
    }
  }, [t]);

  useEffect(() => {
    fetchActivities();
  }, [fetchActivities]);

  const handleEdit = (activity: Activity) => {
    setEditingActivity(activity);
    setIsEditorOpen(true);
  };

  const handleCreate = () => {
    setEditingActivity(null);
    setIsEditorOpen(true);
  };

  const handleDelete = async (id: number) => {
    if (confirm(t('admin.activities.delete_confirm'))) {
      try {
        await ActivityService.delete(id);
        fetchActivities();
      } catch (err) {
        alert(t('common.error_delete'));
      }
    }
  };

  return (
    <div className="p-6 max-w-7xl mx-auto">
      <ActivityAdminHeader onCreate={handleCreate} />

      {error && (
        <div className="bg-red-50 text-red-800 p-4 rounded-xl mb-6 flex items-center gap-3 border border-red-200">
          <AlertCircle className="w-5 h-5" />
          {error}
        </div>
      )}

      {loading ? (
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
          {[1, 2, 3].map(i => <div key={i} className="h-64 bg-slate-100 rounded-2xl animate-pulse"></div>)}
        </div>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {activities.map(activity => (
            <ActivityAdminCard
              key={activity.id}
              activity={activity}
              onEdit={handleEdit}
              onDelete={handleDelete}
            />
          ))}
        </div>
      )}

      <ActivityEditorModal
        isOpen={isEditorOpen}
        onClose={() => setIsEditorOpen(false)}
        activity={editingActivity}
        onSaved={fetchActivities}
      />
    </div>
  );
}

import { useEffect, useState } from "react";
import { AnnouncementService, type Announcement } from "../../services/AnnouncementService";
import {
    Megaphone,
    Save,
    Eye,
    EyeOff,
    AlertCircle,
    CheckCircle2,
    Info,
    ExternalLink,
    Languages
} from "lucide-react";

export default function AnnouncementManager() {
    const [announcement, setAnnouncement] = useState<Announcement | null>(null);
    const [loading, setLoading] = useState(true);
    const [saving, setSaving] = useState(false);
    const [success, setSuccess] = useState(false);
    const [error, setError] = useState<string | null>(null);
    const [activeLang, setActiveLang] = useState<'ca' | 'es' | 'en'>('ca');

    useEffect(() => {
        fetchAnnouncement();
    }, []);

    const fetchAnnouncement = async () => {
        setLoading(true);
        try {
            const data = await AnnouncementService.getLatest();
            if (data && !data.translations) {
                data.translations = {
                    ca: data.message,
                    es: data.message,
                    en: data.message
                };
            }
            setAnnouncement(data);
        } catch (err) {
            console.error(err);
            setError("Error al carregar la configuració");
        } finally {
            setLoading(false);
        }
    };

    const handleSave = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!announcement) return;

        setSaving(true);
        setSuccess(false);
        setError(null);

        try {
            // Update the main message with the active language content for backward compatibility
            const updatedAnnouncement = {
                ...announcement,
                message: announcement.translations?.[activeLang] || announcement.message
            };
            await AnnouncementService.update(updatedAnnouncement);
            setSuccess(true);
            setTimeout(() => setSuccess(false), 3000);
        } catch (err) {
            console.error(err);
            setError("Error al guardar els canvis. Recorda carregar la migració de la base de dades.");
        } finally {
            setSaving(false);
        }
    };

    const handleMessageChange = (val: string) => {
        if (!announcement) return;
        const newTranslations = {
            ...(announcement.translations || { ca: announcement.message, es: announcement.message, en: announcement.message }),
            [activeLang]: val
        };
        setAnnouncement({
            ...announcement,
            translations: newTranslations
        });
    };

    const toggleActive = async () => {
        if (!announcement) return;
        const newState = !announcement.is_active;

        try {
            await AnnouncementService.toggleActive(newState);
            setAnnouncement({ ...announcement, is_active: newState });
        } catch (err) {
            console.error(err);
            alert("Error al canviar l'estat");
        }
    };

    if (loading) {
        return (
            <div className="p-8 flex justify-center items-center h-64">
                <div className="w-8 h-8 border-4 border-primary/20 border-t-primary rounded-full animate-spin"></div>
            </div>
        );
    }

    if (!announcement) {
        return (
            <div className="p-8 text-center text-slate-500">
                No s'ha trobat la configuració del banner.
            </div>
        );
    }

    const previewMessage = announcement.translations?.[activeLang] || announcement.message;

    return (
        <div className="p-6 max-w-4xl mx-auto">
            <div className="flex justify-between items-center mb-8">
                <div>
                    <h1 className="text-3xl font-bold text-slate-800 dark:text-white">Banner d'Anuncis</h1>
                    <p className="text-slate-500 text-sm mt-1">Configura missatges globals a la part superior de la web.</p>
                </div>
                <button
                    onClick={toggleActive}
                    className={`flex items-center gap-2 px-6 py-2.5 rounded-xl font-bold transition-all shadow-md ${announcement.is_active
                        ? 'bg-green-100 text-green-700 hover:bg-green-200 border border-green-200'
                        : 'bg-slate-100 text-slate-600 hover:bg-slate-200 border border-slate-200'
                        }`}
                >
                    {announcement.is_active ? (
                        <><Eye className="w-5 h-5" /> Actiu</>
                    ) : (
                        <><EyeOff className="w-5 h-5" /> Ocult</>
                    )}
                </button>
            </div>

            <form onSubmit={handleSave} className="space-y-6">
                <div className="bg-white dark:bg-slate-800 rounded-3xl p-8 shadow-sm border border-slate-100 dark:border-slate-700 space-y-6">

                    {/* Preview */}
                    <div className="space-y-3">
                        <label className="text-sm font-bold text-slate-500 uppercase tracking-wider">Preview del Banner ({activeLang.toUpperCase()})</label>
                        <div className={`${{ info: 'bg-primary', warning: 'bg-amber-500', success: 'bg-emerald-500' }[announcement.type]
                            } p-3 rounded-xl text-white text-center font-bold text-sm shadow-inner flex items-center justify-center gap-2 max-w-2xl mx-auto overflow-hidden ring-4 ring-slate-100 dark:ring-slate-700/50`}>
                            <Megaphone size={16} />
                            <span className="truncate">{previewMessage || "Escriu un missatge..."}</span>
                            {announcement.link && <ExternalLink size={14} className="opacity-70" />}
                        </div>
                    </div>

                    <hr className="border-slate-100 dark:border-slate-700" />

                    {/* Language Selector */}
                    <div className="flex bg-slate-100 dark:bg-slate-900 p-1 rounded-2xl">
                        {(['ca', 'es', 'en'] as const).map((lang) => (
                            <button
                                key={lang}
                                type="button"
                                onClick={() => setActiveLang(lang)}
                                className={`flex-1 flex items-center justify-center gap-2 py-2.5 rounded-xl text-sm font-bold transition-all ${activeLang === lang
                                    ? 'bg-white dark:bg-slate-800 text-primary shadow-sm'
                                    : 'text-slate-500 hover:text-slate-700 dark:hover:text-slate-300'
                                    }`}
                            >
                                <Languages size={16} />
                                {lang === 'ca' ? 'Català' : lang === 'es' ? 'Castellano' : 'English'}
                            </button>
                        ))}
                    </div>

                    {/* Message Input */}
                    <div className="space-y-2">
                        <label className="block text-sm font-bold text-slate-700 dark:text-slate-200 text-left">Text del Missatge ({activeLang.toUpperCase()})</label>
                        <textarea
                            required
                            value={announcement.translations?.[activeLang] || ''}
                            onChange={(e) => handleMessageChange(e.target.value)}
                            rows={3}
                            className="w-full px-4 py-3 rounded-xl border border-slate-200 dark:border-slate-600 bg-slate-50 dark:bg-slate-900 text-slate-900 dark:text-white focus:ring-2 focus:ring-primary focus:border-transparent outline-none transition-all"
                            placeholder={`Missatge en ${activeLang === 'ca' ? 'Català' : activeLang === 'es' ? 'Castellano' : 'English'}...`}
                        />
                    </div>

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                        {/* Type Selector */}
                        <div className="space-y-2">
                            <label className="block text-sm font-bold text-slate-700 dark:text-slate-200">Tipus d'Alerta</label>
                            <div className="grid grid-cols-3 gap-2">
                                {[
                                    { value: 'info', label: 'Info', color: 'bg-primary' },
                                    { value: 'warning', label: 'Alerta', color: 'bg-amber-500' },
                                    { value: 'success', label: 'Èxit', color: 'bg-emerald-500' },
                                ].map((t) => (
                                    <button
                                        key={t.value}
                                        type="button"
                                        onClick={() => setAnnouncement({ ...announcement, type: t.value as any })}
                                        className={`px-3 py-3 rounded-xl font-bold text-sm border-2 transition-all flex items-center justify-center gap-2 ${announcement.type === t.value
                                            ? 'border-primary bg-primary/5 text-primary'
                                            : 'border-transparent bg-slate-50 dark:bg-slate-900 text-slate-500'
                                            }`}
                                    >
                                        <div className={`w-3 h-3 rounded-full ${t.color}`}></div>
                                        {t.label}
                                    </button>
                                ))}
                            </div>
                        </div>

                        {/* Link Input */}
                        <div className="space-y-2">
                            <label className="block text-sm font-bold text-slate-700 dark:text-slate-200">Enllaç (Opcional)</label>
                            <input
                                type="url"
                                value={announcement.link || ''}
                                onChange={(e) => setAnnouncement({ ...announcement, link: e.target.value })}
                                className="w-full px-4 py-3 rounded-xl border border-slate-200 dark:border-slate-600 bg-slate-50 dark:bg-slate-900 text-slate-900 dark:text-white focus:ring-2 focus:ring-primary focus:border-transparent outline-none transition-all"
                                placeholder="https://..."
                            />
                        </div>
                    </div>
                </div>

                {/* Feedback Messages */}
                {error && (
                    <div className="flex items-center gap-3 p-4 bg-red-100 border border-red-200 text-red-700 rounded-xl animate-shake">
                        <AlertCircle size={20} />
                        <p className="font-medium">{error}</p>
                    </div>
                )}

                {success && (
                    <div className="flex items-center gap-3 p-4 bg-green-100 border border-green-200 text-green-700 rounded-xl animate-in fade-in slide-in-from-top-2">
                        <CheckCircle2 size={20} />
                        <p className="font-medium">Canvis guardats correctament!</p>
                    </div>
                )}

                {/* Action Buttons */}
                <div className="flex gap-4 items-center">
                    <button
                        disabled={saving}
                        type="submit"
                        className="flex-1 bg-primary hover:bg-primary/90 text-white font-bold py-4 rounded-2xl flex items-center justify-center gap-3 shadow-lg shadow-primary/30 transition-all hover:scale-[1.01] active:scale-[0.99] disabled:opacity-50"
                    >
                        {saving ? (
                            <div className="w-6 h-6 border-3 border-white/30 border-t-white rounded-full animate-spin"></div>
                        ) : (
                            <>
                                <Save size={20} />
                                Guardar Configuració
                            </>
                        )}
                    </button>
                    <div className="flex items-center gap-2 p-4 bg-slate-100 dark:bg-slate-800 rounded-2xl border border-slate-200 dark:border-slate-700 text-slate-500 dark:text-slate-400">
                        <Info size={18} />
                        <p className="text-xs">L'actualització és instantània per a tots els usuaris.</p>
                    </div>
                </div>
            </form>
        </div>
    );
}

import { useEffect, useState } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { useTranslation } from 'react-i18next';
import { supabase } from '../../lib/supabase';
import {
    Save,
    ChevronLeft,
    Wand2,
    Image as ImageIcon,
    Link as LinkIcon,
    Calendar as CalendarIcon,
    Info
} from 'lucide-react';
import { ImageUpload } from '../../components/admin/ImageUpload';
import { TranslationService } from '../../services/TranslationService';
import ReactQuill from 'react-quill-new';
import 'react-quill-new/dist/quill.snow.css';

export default function NewsEditorPage() {
    const { id } = useParams<{ id: string }>();
    const navigate = useNavigate();
    const { t } = useTranslation();
    const [loading, setLoading] = useState(id !== 'new');
    const [saving, setSaving] = useState(false);
    const [activeLang, setActiveLang] = useState<'ca' | 'es' | 'en'>('es');
    const [isTranslating, setIsTranslating] = useState(false);

    const [formData, setFormData] = useState({
        title: '',
        slug: '',
        content: '',
        excerpt: '',
        image_url: '',
        news_url: '',
        sources: '',
        published: false,
        event_date: '',
        translations: {
            ca: { title: '', excerpt: '', content: '' },
            es: { title: '', excerpt: '', content: '' },
            en: { title: '', excerpt: '', content: '' }
        } as Record<string, { title: string; excerpt: string; content: string }>
    });

    useEffect(() => {
        const fetchArticle = async () => {
            try {
                const { data, error } = await supabase
                    .from('news')
                    .select('*')
                    .eq('id', id)
                    .single();

                if (error) throw error;
                if (data) {
                    setFormData({
                        title: data.title,
                        slug: data.slug || '',
                        content: data.content || '',
                        excerpt: data.excerpt || '',
                        image_url: data.image_url || '',
                        news_url: data.news_url || '',
                        sources: data.sources || '',
                        published: data.published,
                        event_date: data.event_date ? new Date(data.event_date).toISOString().slice(0, 16) : '',
                        translations: {
                            ca: { title: '', excerpt: '', content: '' },
                            es: { title: data.title, excerpt: data.excerpt || '', content: data.content || '' },
                            en: { title: '', excerpt: '', content: '' },
                            ...(data.translations || {})
                        }
                    });
                }
            } catch (error) {
                console.error('Error fetching article:', error);
                alert('Error cargando la noticia');
                navigate('/admin/news');
            } finally {
                setLoading(false);
            }
        };

        if (id && id !== 'new') {
            fetchArticle();
        }
    }, [id, navigate]);

    const generateSlug = (text: string) => {
        return text
            .toLowerCase()
            .normalize('NFD')
            .replace(/[\u0300-\u036f]/g, '')
            .replace(/[^a-z0-9]+/g, '-')
            .replace(/(^-|-$)+/g, '');
    };

    const updateTranslationField = (lang: string, field: string, value: string) => {
        setFormData(prev => {
            const newTranslations = {
                ...prev.translations,
                [lang]: {
                    ...prev.translations[lang],
                    [field]: value
                }
            };

            let newSlug = prev.slug;
            if (field === 'title' && lang === 'es' && id === 'new' && !prev.slug) {
                newSlug = generateSlug(value);
            }

            const updatedData = {
                ...prev,
                translations: newTranslations,
                slug: newSlug
            };

            if (lang === 'es') {
                (updatedData as any)[field] = value;
            }

            return updatedData;
        });
    };

    const handleAutoTranslate = async () => {
        const sourceContent = formData.translations[activeLang];
        if (!sourceContent.title) {
            alert('Rellena el título en el idioma actual primero');
            return;
        }

        setIsTranslating(true);
        try {
            const targetLangs = (['ca', 'es', 'en'] as const).filter(l => l !== activeLang);
            const updatedTranslations = { ...formData.translations };

            for (const lang of targetLangs) {
                const translated = await TranslationService.translateNews(sourceContent, lang, activeLang);
                if (translated) {
                    updatedTranslations[lang] = {
                        title: translated.title || '',
                        excerpt: translated.excerpt || '',
                        content: translated.content || ''
                    };
                }
            }

            setFormData(prev => ({ ...prev, translations: updatedTranslations }));
        } catch (error) {
            console.error('Translation error:', error);
            alert('Error en la traducción');
        } finally {
            setIsTranslating(false);
        }
    };

    const handleSave = async () => {
        if (!formData.translations.es.title.trim() && !formData.title.trim()) {
            alert('El título es obligatorio');
            return;
        }

        setSaving(true);
        try {
            const payload = {
                title: formData.translations.es.title || formData.title,
                slug: formData.slug || generateSlug(formData.translations.es.title || formData.title),
                content: formData.translations.es.content || formData.content,
                excerpt: formData.translations.es.excerpt || formData.excerpt,
                image_url: formData.image_url || null,
                news_url: formData.news_url || null,
                sources: formData.sources || null,
                published: formData.published,
                event_date: formData.event_date ? new Date(formData.event_date).toISOString() : null,
                translations: formData.translations,
                updated_at: new Date().toISOString()
            };

            if (id && id !== 'new') {
                const { error } = await supabase.from('news').update(payload).eq('id', id);
                if (error) throw error;
            } else {
                const { error } = await supabase.from('news').insert([payload]);
                if (error) throw error;
            }

            navigate('/admin/news');
        } catch (error) {
            console.error('Error saving article:', error);
            alert('Error al guardar');
        } finally {
            setSaving(false);
        }
    };

    if (loading) {
        return (
            <div className="flex items-center justify-center min-h-[400px] pt-20">
                <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600"></div>
            </div>
        );
    }

    return (
        <div className="max-w-6xl mx-auto pb-20">
            <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4 mb-8">
                <div className="flex items-center gap-4">
                    <button
                        onClick={() => navigate('/admin/news')}
                        className="p-3 bg-white hover:bg-slate-50 rounded-2xl border border-slate-200 shadow-sm transition-all text-slate-500 active:scale-95"
                    >
                        <ChevronLeft className="w-6 h-6" />
                    </button>
                    <div>
                        <h1 className="text-2xl font-black text-slate-900 leading-none mb-1">
                            {id === 'new' ? 'Nova Notícia' : 'Editar Notícia'}
                        </h1>
                        <div className="flex items-center gap-2">
                            <span className="text-[10px] font-black uppercase tracking-widest text-slate-400">URL:</span>
                            <code className="text-xs text-blue-600 font-bold bg-blue-50 px-2 py-0.5 rounded-lg">
                                /noticies/{formData.slug || '...'}
                            </code>
                        </div>
                    </div>
                </div>

                <div className="flex items-center gap-3 w-full sm:w-auto">
                    <button
                        onClick={handleSave}
                        disabled={saving}
                        className="flex-1 sm:flex-none flex items-center justify-center gap-2 px-8 py-4 bg-blue-600 text-white rounded-2xl font-black shadow-xl shadow-blue-200 hover:bg-blue-700 transition-all active:scale-95 disabled:opacity-50"
                    >
                        <Save className="w-5 h-5" />
                        {saving ? t('common.saving') : t('common.save')}
                    </button>
                </div>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
                <div className="lg:col-span-2 space-y-6">
                    <div className="bg-white rounded-[2.5rem] border border-slate-200 shadow-sm overflow-hidden border-b-4 border-b-slate-100">
                        <div className="flex items-center justify-between p-6 border-b border-slate-100 bg-slate-50/50">
                            <div className="flex bg-white p-1 rounded-xl border border-slate-200 shadow-inner">
                                {(['ca', 'es', 'en'] as const).map((lang) => (
                                    <button
                                        key={lang}
                                        onClick={() => setActiveLang(lang)}
                                        className={`px-5 py-2 rounded-lg text-xs font-black transition-all ${activeLang === lang
                                            ? 'bg-blue-600 text-white shadow-lg'
                                            : 'text-slate-400 hover:text-slate-600'
                                            }`}
                                    >
                                        {lang.toUpperCase()}
                                    </button>
                                ))}
                            </div>
                            <button
                                onClick={handleAutoTranslate}
                                disabled={isTranslating}
                                className="flex items-center gap-2 px-6 py-2 bg-amber-500 text-white rounded-xl text-xs font-black hover:bg-amber-600 transition-all shadow-lg shadow-amber-100 disabled:opacity-50"
                            >
                                <Wand2 className={`w-4 h-4 ${isTranslating ? 'animate-pulse' : ''}`} />
                                {isTranslating ? 'Traduint...' : 'Auto-traduir'}
                            </button>
                        </div>

                        <div className="p-8 sm:p-12 space-y-8">
                            <div>
                                <label className="block text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-3">
                                    Títol de la notícia ({activeLang})
                                </label>
                                <input
                                    type="text"
                                    value={formData.translations[activeLang]?.title || ''}
                                    onChange={e => updateTranslationField(activeLang, 'title', e.target.value)}
                                    className="w-full px-0 text-4xl sm:text-5xl font-black text-slate-900 border-none focus:ring-0 placeholder:text-slate-100 bg-transparent leading-tight"
                                    placeholder="Escriu un títol impactant..."
                                />
                            </div>

                            <div>
                                <label className="block text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-3">
                                    Resum o entradilla
                                </label>
                                <textarea
                                    value={formData.translations[activeLang]?.excerpt || ''}
                                    onChange={e => updateTranslationField(activeLang, 'excerpt', e.target.value)}
                                    className="w-full px-6 py-5 bg-slate-50 border-2 border-slate-100 rounded-3xl focus:ring-0 focus:border-blue-200 outline-none transition-all resize-none text-lg text-slate-600 font-medium leading-relaxed italic"
                                    rows={3}
                                    placeholder="Un breu resum que convidi a llegir més..."
                                />
                            </div>

                            <div className="space-y-4">
                                <label className="block text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-1">
                                    Cos de la notícia
                                </label>
                                <div className="relative">
                                    <ReactQuill
                                        theme="snow"
                                        value={formData.translations[activeLang]?.content || ''}
                                        onChange={value => updateTranslationField(activeLang, 'content', value)}
                                        modules={{
                                            toolbar: [
                                                [{ 'header': [1, 2, 3, false] }],
                                                ['bold', 'italic', 'underline', 'strike'],
                                                [{ 'list': 'ordered' }, { 'list': 'bullet' }],
                                                ['link', 'blockquote', 'image'],
                                                ['clean']
                                            ],
                                        }}
                                        className="big-editor"
                                    />
                                </div>
                            </div>
                        </div>
                    </div>
                </div>

                <div className="space-y-6">
                    <div className="bg-white rounded-[2rem] border border-slate-200 shadow-sm p-8">
                        <div className="flex items-center justify-between gap-4">
                            <div className="flex items-center gap-3">
                                <div className={`w-3 h-3 rounded-full animate-pulse ${formData.published ? 'bg-green-500' : 'bg-amber-400'}`} />
                                <span className="font-bold text-slate-900">{formData.published ? 'Publicada' : 'Esborrany'}</span>
                            </div>
                            <label className="relative inline-flex items-center cursor-pointer">
                                <input
                                    type="checkbox"
                                    checked={formData.published}
                                    onChange={e => setFormData(prev => ({ ...prev, published: e.target.checked }))}
                                    className="sr-only peer"
                                />
                                <div className="w-11 h-6 bg-slate-200 peer-focus:outline-none rounded-full peer dark:bg-slate-700 peer-checked:after:translate-x-full peer-checked:after:border-white after:content-[''] after:absolute after:top-[2px] after:left-[2px] after:bg-white after:border-gray-300 after:border after:rounded-full after:h-5 after:w-5 after:transition-all peer-checked:bg-blue-600"></div>
                            </label>
                        </div>
                    </div>

                    <div className="bg-white rounded-[2rem] border border-slate-200 shadow-sm p-8">
                        <div className="flex items-center gap-2 mb-6 text-slate-900 font-black uppercase text-[10px] tracking-widest">
                            <ImageIcon className="w-4 h-4 text-blue-600" />
                            Imatge destacada
                        </div>
                        <ImageUpload
                            value={formData.image_url}
                            onUpload={(url) => setFormData(prev => ({ ...prev, image_url: url || '' }))}
                            folder="news"
                        />
                    </div>

                    <div className="bg-white rounded-[2rem] border border-slate-200 shadow-sm p-8 space-y-6">
                        <div className="flex items-center gap-2 mb-2 text-slate-900 font-black uppercase text-[10px] tracking-widest">
                            <LinkIcon className="w-4 h-4 text-blue-600" />
                            Configuració avanzada
                        </div>

                        <div className="space-y-1">
                            <label className="text-[10px] font-bold text-slate-400 uppercase tracking-wider ml-1">Enllaç Permanent (Slug)</label>
                            <input
                                type="text"
                                value={formData.slug}
                                onChange={e => setFormData(prev => ({ ...prev, slug: generateSlug(e.target.value) }))}
                                className="w-full px-4 py-3 bg-slate-50 border-2 border-slate-100 rounded-2xl text-xs font-mono font-bold focus:border-blue-200 outline-none transition-all"
                                placeholder="ej: taller-de-familias"
                            />
                        </div>

                        <div className="space-y-1">
                            <label className="text-[10px] font-bold text-slate-400 uppercase tracking-wider ml-1">Font de la notícia</label>
                            <input
                                type="text"
                                value={formData.sources}
                                onChange={e => setFormData(prev => ({ ...prev, sources: e.target.value }))}
                                className="w-full px-4 py-3 bg-slate-50 border-2 border-slate-100 rounded-2xl text-sm font-bold focus:border-blue-200 outline-none transition-all"
                                placeholder="Ej: Diari de Sant Feliu"
                            />
                        </div>

                        <div className="space-y-1">
                            <label className="text-[10px] font-bold text-slate-400 uppercase tracking-wider ml-1">URL Externa</label>
                            <input
                                type="url"
                                value={formData.news_url}
                                onChange={e => setFormData(prev => ({ ...prev, news_url: e.target.value }))}
                                className="w-full px-4 py-3 bg-slate-50 border-2 border-slate-100 rounded-2xl text-sm font-bold focus:border-blue-200 outline-none transition-all"
                                placeholder="https://..."
                            />
                        </div>
                    </div>

                    <div className="bg-white rounded-[2rem] border border-slate-200 shadow-sm p-8">
                        <div className="flex items-center gap-2 mb-6 text-slate-900 font-black uppercase text-[10px] tracking-widest">
                            <CalendarIcon className="w-4 h-4 text-blue-600" />
                            Data de l'Esdeveniment
                        </div>
                        <input
                            type="datetime-local"
                            value={formData.event_date}
                            onChange={e => setFormData(prev => ({ ...prev, event_date: e.target.value }))}
                            className="w-full px-5 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl text-sm font-bold focus:border-blue-200 outline-none transition-all"
                        />
                        <div className="mt-4 p-4 bg-slate-50 rounded-2xl flex items-start gap-3">
                            <Info className="w-4 h-4 text-slate-400 shrink-0 mt-0.5" />
                            <p className="text-[10px] text-slate-500 font-medium leading-relaxed">
                                Si aquesta notícia anuncia una activitat concreta, posa la fecha aquí per a que aparegui un calendari destacat a la pàgina.
                            </p>
                        </div>
                    </div>
                </div>
            </div>

            <style>{`
        .big-editor .ql-container {
          min-height: 500px;
          border-bottom-left-radius: 2rem;
          border-bottom-right-radius: 2rem;
          font-family: inherit;
          font-size: 1.125rem;
          border: 2px solid #f1f5f9 !important;
          border-top: none !important;
        }
        .big-editor .ql-toolbar {
          border-top-left-radius: 1.5rem;
          border-top-right-radius: 1.5rem;
          background: #f8fafc;
          border: 2px solid #f1f5f9 !important;
          padding: 1rem !important;
        }
        .big-editor .ql-editor {
          padding: 2rem !important;
        }
        .big-editor .ql-editor.ql-blank::before {
          left: 2rem !important;
          color: #e2e8f0;
          font-style: normal;
        }
      `}</style>
        </div>
    );
}

import { useEffect, useState } from 'react';
import { supabase } from '../../lib/supabase';
import { 
  Plus, 
  Search, 
  Edit, 
  Trash2, 
  Eye, 
  EyeOff,
  Bell,
  AlertCircle,
  Info,
  Calendar,
  RefreshCw
} from 'lucide-react';
import { format } from 'date-fns';

interface Notification {
  id: string;
  title: string;
  message: string | null;
  type: 'news' | 'alert' | 'info';
  link: string | null;
  start_at: string;
  end_at: string | null;
  active: boolean;
  created_at: string;
}

export default function NotificationManager() {
  const [notifications, setNotifications] = useState<Notification[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchText, setSearchText] = useState('');
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  
  const [formData, setFormData] = useState<{
    title: string;
    message: string;
    type: 'news' | 'alert' | 'info';
    link: string;
    start_at: string;
    end_at: string;
    active: boolean;
  }>({
    title: '',
    message: '',
    type: 'info',
    link: '',
    start_at: '',
    end_at: '',
    active: true
  });
  
  const [saving, setSaving] = useState(false);

  useEffect(() => {
    fetchNotifications();
  }, []);

  const fetchNotifications = async () => {
    setLoading(true);
    try {
      const { data, error } = await supabase
        .from('notifications')
        .select('*')
        .order('created_at', { ascending: false });

      if (error) throw error;
      setNotifications(data || []);
    } catch (error) {
      console.error('Error fetching notifications:', error);
      alert('Error al cargar notificaciones');
    } finally {
      setLoading(false);
    }
  };

  const handleCreate = () => {
    setEditingId(null);
    setFormData({
      title: '',
      message: '',
      type: 'info',
      link: '',
      start_at: new Date().toISOString().slice(0, 16),
      end_at: '',
      active: true
    });
    setIsModalOpen(true);
  };

  const handleEdit = (notification: Notification) => {
    setEditingId(notification.id);
    setFormData({
      title: notification.title,
      message: notification.message || '',
      type: notification.type,
      link: notification.link || '',
      start_at: new Date(notification.start_at).toISOString().slice(0, 16),
      end_at: notification.end_at ? new Date(notification.end_at).toISOString().slice(0, 16) : '',
      active: notification.active
    });
    setIsModalOpen(true);
  };

  const handleDelete = async (id: string) => {
    if (!confirm('¿Estás seguro de eliminar esta notificación?')) return;
    
    try {
      const { error } = await supabase.from('notifications').delete().eq('id', id);
      if (error) throw error;
      setNotifications(prev => prev.filter(n => n.id !== id));
    } catch (error) {
      console.error('Error deleting:', error);
      alert('Error al eliminar');
    }
  };

  const handleToggleActive = async (notification: Notification) => {
    const newActive = !notification.active;
    try {
      const { error } = await supabase
        .from('notifications')
        .update({ active: newActive })
        .eq('id', notification.id);

      if (error) throw error;
      
      setNotifications(prev => prev.map(n => 
        n.id === notification.id ? { ...n, active: newActive } : n
      ));
    } catch (error) {
      console.error('Error toggling active:', error);
      alert('Error al actualizar estado');
    }
  };

  const handleSave = async () => {
    if (!formData.title.trim()) {
      alert('El título es obligatorio');
      return;
    }

    setSaving(true);
    try {
      const payload = {
        title: formData.title,
        message: formData.message || null,
        type: formData.type,
        link: formData.link || null,
        start_at: new Date(formData.start_at).toISOString(),
        end_at: formData.end_at ? new Date(formData.end_at).toISOString() : null,
        active: formData.active
      };

      if (editingId) {
        const { error } = await supabase
          .from('notifications')
          .update(payload)
          .eq('id', editingId);
        if (error) throw error;
      } else {
        const { error } = await supabase
          .from('notifications')
          .insert([payload]);
        if (error) throw error;
      }

      setIsModalOpen(false);
      fetchNotifications();
    } catch (error) {
      console.error('Error saving:', error);
      alert('Error al guardar');
    } finally {
      setSaving(false);
    }
  };

  const filteredNotifications = notifications.filter(n =>
    n.title.toLowerCase().includes(searchText.toLowerCase())
  );

  const getIcon = (type: string) => {
    switch (type) {
      case 'alert': return <AlertCircle className="w-5 h-5 text-red-500" />;
      case 'news': return <Calendar className="w-5 h-5 text-blue-500" />;
      default: return <Info className="w-5 h-5 text-slate-500" />;
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div>
          <h1 className="text-2xl font-bold text-slate-900">Gestor de Notificaciones</h1>
          <p className="text-slate-500">Administra los avisos y alertas de la campanita</p>
        </div>
        <div className="flex gap-2">
          <button
            onClick={fetchNotifications}
            className="p-2 text-slate-600 hover:bg-slate-100 rounded-lg transition-colors"
          >
            <RefreshCw className={`w-5 h-5 ${loading ? 'animate-spin' : ''}`} />
          </button>
          <button 
            onClick={handleCreate}
            className="flex items-center gap-2 px-4 py-2 bg-blue-600 text-white rounded-lg font-medium hover:bg-blue-700 transition-colors shadow-sm"
          >
            <Plus className="w-4 h-4" />
            Nueva Notificación
          </button>
        </div>
      </div>

      <div className="bg-white p-4 rounded-xl shadow-sm border border-slate-200">
        <div className="relative">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 w-4 h-4" />
          <input
            type="text"
            placeholder="Buscar notificaciones..."
            className="w-full pl-10 pr-4 py-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
            value={searchText}
            onChange={e => setSearchText(e.target.value)}
          />
        </div>
      </div>

      {loading ? (
        <div className="flex justify-center py-12">
          <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-blue-600"></div>
        </div>
      ) : filteredNotifications.length === 0 ? (
        <div className="bg-white rounded-2xl border border-slate-200 p-8 text-center text-slate-500">
          <Bell className="w-12 h-12 mx-auto mb-3 opacity-20" />
          No hay notificaciones
        </div>
      ) : (
        <div className="grid gap-4">
          {filteredNotifications.map(notification => (
            <div 
              key={notification.id}
              className={`bg-white rounded-xl border p-5 shadow-sm hover:shadow-md transition-shadow ${
                notification.active ? 'border-slate-200' : 'border-slate-100 bg-slate-50 opacity-75'
              }`}
            >
              <div className="flex items-start justify-between gap-4">
                <div className="flex items-start gap-4">
                  <div className="mt-1 p-2 bg-slate-50 rounded-lg">
                    {getIcon(notification.type)}
                  </div>
                  <div>
                    <div className="flex items-center gap-2 mb-1">
                      <h3 className="font-semibold text-slate-900">{notification.title}</h3>
                      <span className={`px-2 py-0.5 text-xs font-bold uppercase rounded-full ${
                        notification.type === 'alert' ? 'bg-red-100 text-red-700' :
                        notification.type === 'news' ? 'bg-blue-100 text-blue-700' :
                        'bg-slate-100 text-slate-700'
                      }`}>
                        {notification.type}
                      </span>
                      {!notification.active && (
                         <span className="px-2 py-0.5 text-xs font-bold uppercase rounded-full bg-slate-200 text-slate-500">
                           Inactiva
                         </span>
                      )}
                    </div>
                    {notification.message && (
                      <p className="text-sm text-slate-500 mb-2">{notification.message}</p>
                    )}
                    <div className="flex flex-wrap gap-x-4 gap-y-1 text-xs text-slate-400">
                        <span className="flex items-center gap-1">
                            <span className="font-medium">Inicio:</span>
                            {format(new Date(notification.start_at), 'dd/MM/yyyy HH:mm')}
                        </span>
                        {notification.end_at && (
                             <span className="flex items-center gap-1">
                                <span className="font-medium">Fin:</span>
                                {format(new Date(notification.end_at), 'dd/MM/yyyy HH:mm')}
                            </span>
                        )}
                        {notification.link && (
                            <span className="truncate max-w-[200px]" title={notification.link}>
                                🔗 {notification.link}
                            </span>
                        )}
                    </div>
                  </div>
                </div>

                <div className="flex items-center gap-1">
                  <button
                    onClick={() => handleToggleActive(notification)}
                    className={`p-2 rounded-lg transition-colors ${
                      notification.active
                        ? 'text-green-600 hover:bg-green-50'
                        : 'text-slate-400 hover:bg-slate-100'
                    }`}
                    title={notification.active ? 'Desactivar' : 'Activar'}
                  >
                    {notification.active ? <Eye className="w-5 h-5" /> : <EyeOff className="w-5 h-5" />}
                  </button>
                  <button
                    onClick={() => handleEdit(notification)}
                    className="p-2 text-blue-600 hover:bg-blue-50 rounded-lg transition-colors"
                  >
                    <Edit className="w-5 h-5" />
                  </button>
                  <button
                    onClick={() => handleDelete(notification.id)}
                    className="p-2 text-red-600 hover:bg-red-50 rounded-lg transition-colors"
                  >
                    <Trash2 className="w-5 h-5" />
                  </button>
                </div>
              </div>
            </div>
          ))}
        </div>
      )}

      {isModalOpen && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
          <div className="bg-white rounded-2xl shadow-xl w-full max-w-lg max-h-[90vh] overflow-y-auto">
            <div className="p-6 border-b border-slate-200">
              <h2 className="text-xl font-bold text-slate-900">
                {editingId ? 'Editar Notificación' : 'Nueva Notificación'}
              </h2>
            </div>
            <div className="p-6 space-y-4">
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Título *</label>
                <input
                  type="text"
                  value={formData.title}
                  onChange={e => setFormData(prev => ({ ...prev, title: e.target.value }))}
                  className="w-full px-4 py-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                  placeholder="Ej: Fiesta del Chocolate"
                />
              </div>

              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Mensaje (Opcional)</label>
                <textarea
                  value={formData.message}
                  onChange={e => setFormData(prev => ({ ...prev, message: e.target.value }))}
                  className="w-full px-4 py-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                  rows={3}
                  placeholder="Detalles breves..."
                />
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                   <label className="block text-sm font-medium text-slate-700 mb-1">Tipo</label>
                   <select
                     value={formData.type}
                     onChange={e => setFormData(prev => ({ ...prev, type: e.target.value as any }))}
                     className="w-full px-4 py-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                   >
                     <option value="info">Información</option>
                     <option value="alert">Alerta</option>
                     <option value="news">Noticia</option>
                   </select>
                </div>
                <div>
                   <label className="block text-sm font-medium text-slate-700 mb-1">Enlace (Opcional)</label>
                   <input
                     type="text"
                     value={formData.link}
                     onChange={e => setFormData(prev => ({ ...prev, link: e.target.value }))}
                     className="w-full px-4 py-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                     placeholder="https://..."
                   />
                </div>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                   <label className="block text-sm font-medium text-slate-700 mb-1">Mostrar desde *</label>
                   <input
                     type="datetime-local"
                     value={formData.start_at}
                     onChange={e => setFormData(prev => ({ ...prev, start_at: e.target.value }))}
                     className="w-full px-4 py-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                   />
                </div>
                <div>
                   <label className="block text-sm font-medium text-slate-700 mb-1">Mostrar hasta</label>
                   <input
                     type="datetime-local"
                     value={formData.end_at}
                     onChange={e => setFormData(prev => ({ ...prev, end_at: e.target.value }))}
                     className="w-full px-4 py-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                   />
                   <p className="text-xs text-slate-400 mt-1">Dejar vacío para indefinido</p>
                </div>
              </div>

              <div className="flex items-center gap-2">
                 <input
                   type="checkbox"
                   id="active"
                   checked={formData.active}
                   onChange={e => setFormData(prev => ({ ...prev, active: e.target.checked }))}
                   className="w-4 h-4 text-blue-600 rounded focus:ring-blue-500"
                 />
                 <label htmlFor="active" className="text-sm font-medium text-slate-700">Activo visible</label>
              </div>

            </div>
            <div className="p-6 border-t border-slate-200 flex justify-end gap-3">
              <button
                onClick={() => setIsModalOpen(false)}
                className="px-4 py-2 border border-slate-200 rounded-lg text-slate-700 hover:bg-slate-50 transition-colors"
                disabled={saving}
              >
                Cancelar
              </button>
              <button
                onClick={handleSave}
                disabled={saving}
                className="px-4 py-2 bg-blue-600 text-white rounded-lg font-medium hover:bg-blue-700 transition-colors disabled:opacity-50"
              >
                {saving ? 'Guardando...' : 'Guardar'}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

/**
 * @fileoverview Admin Dashboard for managing inscriptions
 * Refactored to use custom hooks for logic separation (Midudev pattern)
 */

import { useState } from 'react';
import { Loader2, FileSpreadsheet, FileText } from 'lucide-react';
import { useTranslation } from 'react-i18next';

// Hooks
import { useInscriptions } from '../../../hooks/useInscriptions';
import { useFinancialStats } from '../../../hooks/useFinancialStats';

// Services
import { ExportService } from '../../../services/ExportService';

// Components
import { StatsCards } from './StatsCards';
import { FinancialStatsCards } from './FinancialStatsCards';
import { Filters } from './Filters';
import { InscriptionsTable } from './InscriptionsTable';
import { InscriptionDetailsModal } from './InscriptionDetailsModal';
import { InscriptionEditModal } from './InscriptionEditModal';

// Types
import type { InscriptionFlat, InscriptionStatus } from '../../../types/inscription';

export function Dashboard() {
  const { t } = useTranslation();
  // Inscription logic extracted to custom hook
  const {
    inscriptions,
    filteredData,
    isLoading,
    filters,
    setFilter,
    reload,
    handleDelete,
    handleStatusChange,
  } = useInscriptions();

  // Stats logic extracted to custom hook
  const {
    financialStats,
    shopStats,
    reload: reloadStats,
  } = useFinancialStats();

  // Modal state (kept in component as it's UI-specific)
  const [selectedInscription, setSelectedInscription] = useState<InscriptionFlat | null>(null);
  const [editingInscription, setEditingInscription] = useState<InscriptionFlat | null>(null);

  const handleExportExcel = () => {
    ExportService.exportInscriptionsExcel(filteredData, 'full', 'Inscripcions_AFA');
  };

  const handleExportPDF = () => {
    ExportService.exportInscriptionsPDF(filteredData, 'full', 'Inscripcions_AFA');
  };

  const handleReload = () => {
    reload();
    reloadStats();
  };

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div>
          <h2 className="text-2xl font-bold text-slate-900">{t('admin.dashboard.title')}</h2>
          <p className="text-slate-500">{t('admin.dashboard.subtitle')}</p>
        </div>

        <div className="flex gap-2">
          <button
            onClick={handleExportExcel}
            className="bg-green-600 text-white px-4 py-2 rounded-lg hover:bg-green-700 transition flex items-center gap-2 text-sm font-medium"
            title={t('admin.dashboard.export_excel')}
          >
            <FileSpreadsheet className="w-4 h-4" />
            <span className="hidden sm:inline">Excel</span>
          </button>

          <button
            onClick={handleExportPDF}
            className="bg-red-600 text-white px-4 py-2 rounded-lg hover:bg-red-700 transition flex items-center gap-2 text-sm font-medium"
            title={t('admin.dashboard.export_pdf')}
          >
            <FileText className="w-4 h-4" />
            <span className="hidden sm:inline">PDF</span>
          </button>

          <button
            onClick={handleReload}
            className="bg-blue-600 text-white px-4 py-2 rounded-lg hover:bg-blue-700 transition flex items-center gap-2 text-sm font-medium"
          >
            {isLoading ? <Loader2 className="animate-spin w-4 h-4" /> : t('admin.dashboard.update')}
          </button>
        </div>
      </div>

      {/* Stats Cards */}
      <StatsCards inscriptions={inscriptions} />
      <FinancialStatsCards financial={financialStats} shop={shopStats} />

      {/* Table with Filters */}
      <div className="bg-white rounded-xl shadow-sm border border-slate-200">
        <Filters
          course={filters.course}
          setCourse={(value: string) => setFilter('course', value)}
          activity={filters.activity}
          setActivity={(value: string) => setFilter('activity', value)}
          status={filters.status}
          setStatus={(value: string) => setFilter('status', value)}
          search={filters.search}
          setSearch={(value: string) => setFilter('search', value)}
        />

        <InscriptionsTable
          rows={filteredData}
          loading={isLoading}
          onDelete={handleDelete}
          onStatusChange={handleStatusChange}
          onViewDetails={setSelectedInscription}
          onEdit={setEditingInscription}
        />
      </div>

      {/* Modals */}
      <InscriptionDetailsModal
        inscription={selectedInscription}
        onClose={() => setSelectedInscription(null)}
      />

      <InscriptionEditModal
        inscription={editingInscription}
        onClose={() => setEditingInscription(null)}
        onSave={reload}
      />
    </div>
  );
}

import { useEffect, useState } from 'react';
import { supabase } from '../../../lib/supabase';
import { useTranslation } from 'react-i18next';
import { Search, Plus, CheckCircle, XCircle, Download, Edit, Trash2 } from 'lucide-react';
import { EditPaymentModal } from '../../../components/admin/EditPaymentModal';
import { ExportService } from '../../../services/ExportService';

interface Payment {
  id: string;
  student_name: string;
  student_surname: string;
  course: string;
  activities: string[];
  amount: number;
  due_date: string;
  payment_date: string | null;
  status: 'paid' | 'pending' | 'overdue';
  payment_month: number;
  payment_year: number;
  notes?: string;
  bank_reference?: string;
}

export function PaymentsPage() {
  const { t, i18n } = useTranslation();
  const [payments, setPayments] = useState<Payment[]>([]);
  const [loading, setLoading] = useState(true);
  const [filterText, setFilterText] = useState('');
  const [statusFilter, setStatusFilter] = useState('all');
  const [monthFilter, setMonthFilter] = useState('all');
  
  // Modal State
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingPayment, setEditingPayment] = useState<Payment | undefined>(undefined);

  useEffect(() => {
    fetchPayments();
  }, []);

  const fetchPayments = async () => {
    setLoading(true);
    try {
      const { data, error } = await supabase
        .from('payments')
        .select('*')
        .order('due_date', { ascending: false });

      if (error) throw error;
      setPayments(data || []);
    } catch (error) {
      console.error('Error fetching payments:', error);
    } finally {
      setLoading(false);
    }
  };

  const togglePaymentStatus = async (id: string, currentStatus: string) => {
    const newStatus = currentStatus === 'paid' ? 'pending' : 'paid';
    const paymentDate = newStatus === 'paid' ? new Date().toISOString() : null;

    try {
      const { error } = await supabase
        .from('payments')
        .update({ status: newStatus, payment_date: paymentDate })
        .eq('id', id);

      if (error) throw error;
      fetchPayments(); // Refresh list
    } catch (error) {
      console.error('Error updating payment:', error);
      alert(t('admin.payments.update_error'));
    }
  };

  const handleCreate = () => {
      setEditingPayment(undefined);
      setIsModalOpen(true);
  };

  const handleEdit = (payment: Payment) => {
      setEditingPayment(payment);
      setIsModalOpen(true);
  };
  
  const handleDelete = async (id: string) => {
      if (!confirm(t('admin.payments.delete_confirm'))) return;
      try {
          const { error } = await supabase.from('payments').delete().eq('id', id);
          if (error) throw error;
          setPayments(prev => prev.filter(p => p.id !== id));
        } catch (err) {
          console.error(err);
          alert(t('admin.payments.delete_error'));
      }
  };

  const handleSavePayment = async (formData: any) => {
      try {
          if (editingPayment) {
              const { error } = await supabase
                .from('payments')
                .update({ 
                    ...formData, 
                    // Ensure arrays and dates are formatted if needed by Supabase (usually auto)
                 })
                .eq('id', editingPayment.id);
               if (error) throw error;
          } else {
              const { error } = await supabase
                .from('payments')
                .insert([{
                    ...formData,
                    payment_month: new Date(formData.due_date).getMonth() + 1,
                    payment_year: new Date(formData.due_date).getFullYear()
                }]);
               if (error) throw error;
          }
          fetchPayments();
      } catch (err) {
          console.error(err);
          throw err;
      }
  };

  const isOverdue = (p: Payment) => {
    if (p.status === 'paid') return false;
    if (!p.due_date) return false;
    return new Date(p.due_date) < new Date();
  };

  const getStatus = (p: Payment) => {
    if (p.status === 'paid') return 'paid';
    if (isOverdue(p)) return 'overdue';
    return 'pending';
  };

  // Stats
  const totalAmount = payments.reduce((acc, p) => acc + (Number(p.amount) || 0), 0);
  const paidAmount = payments.filter(p => p.status === 'paid').reduce((acc, p) => acc + (Number(p.amount) || 0), 0);
  const pendingAmount = totalAmount - paidAmount;

  const filteredPayments = payments.filter(p => {
    const st = getStatus(p);
    if (statusFilter !== 'all' && st !== statusFilter) return false;
    if (monthFilter !== 'all' && p.payment_month !== Number(monthFilter)) return false;
    
    if (filterText) {
      const search = filterText.toLowerCase();
      return (
        p.student_name.toLowerCase().includes(search) || 
        p.student_surname.toLowerCase().includes(search)
      );
    }
    return true;
  });

  if (loading) return <div className="p-8 text-center">{t('admin.payments.loading')}</div>;

  return (
    <div className="p-6 space-y-6">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div>
          <h1 className="text-2xl font-bold text-slate-900">{t('admin.payments.title')}</h1>
          <p className="text-slate-500">{t('admin.payments.subtitle')}</p>
        </div>
        <div className="flex flex-wrap gap-2">
           <button 
                onClick={() => ExportService.exportPaymentsCSV(payments, 'pagaments')}
                className="flex items-center gap-2 px-3 py-2 bg-white border border-slate-300 text-slate-700 rounded-lg hover:bg-slate-50 transition-colors text-sm font-medium"
            >
             <Download className="w-4 h-4" /> CSV
           </button>
           <button 
                onClick={handleCreate}
                className="flex items-center gap-2 px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 transition-colors shadow-sm"
            >
             <Plus className="w-4 h-4" /> {t('admin.payments.register_button')}
           </button>
        </div>
      </div>

      {/* Stats Cards */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
          <div className="text-sm font-medium text-slate-500">{t('admin.payments.stats.total')}</div>
          <div className="text-3xl font-bold text-slate-900 mt-2">{totalAmount.toFixed(2)}€</div>
        </div>
        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
          <div className="text-sm font-medium text-slate-500">{t('admin.payments.stats.paid')}</div>
          <div className="text-3xl font-bold text-green-600 mt-2">{paidAmount.toFixed(2)}€</div>
          <div className="text-xs text-slate-400 mt-1">{t('admin.payments.stats.percentage_hint', { percentage: ((paidAmount/totalAmount || 0)*100).toFixed(0) })}</div>
        </div>
        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
          <div className="text-sm font-medium text-slate-500">{t('admin.payments.stats.pending')}</div>
          <div className="text-3xl font-bold text-amber-600 mt-2">{pendingAmount.toFixed(2)}€</div>
        </div>
      </div>

      {/* Filters */}
      <div className="bg-white p-4 rounded-xl shadow-sm border border-slate-200 flex flex-wrap gap-4 items-center">
        <div className="relative flex-1 min-w-[200px]">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 w-4 h-4" />
          <input 
            type="text" 
            placeholder={t('admin.payments.search_placeholder')} 
            className="w-full pl-10 pr-4 py-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-primary outline-none"
            value={filterText}
            onChange={e => setFilterText(e.target.value)}
          />
        </div>

        <select 
          className="px-4 py-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-primary outline-none bg-white font-medium"
          value={monthFilter}
          onChange={e => setMonthFilter(e.target.value)}
        >
          <option value="all">{t('admin.payments.all_months')}</option>
          {[...Array(12)].map((_, i) => (
            <option key={i} value={i + 1}>
              {new Date(0, i).toLocaleString(i18n.language === 'es' ? 'es-ES' : 'ca-ES', { month: 'long' })}
            </option>
          ))}
        </select>
        
        <select 
          className="px-4 py-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-primary outline-none bg-white font-medium"
          value={statusFilter}
          onChange={e => setStatusFilter(e.target.value)}
        >
          <option value="all">{t('admin.payments.status_all')}</option>
          <option value="paid">{t('admin.payments.status.paid')}</option>
          <option value="pending">{t('admin.payments.status.pending')}</option>
          <option value="overdue">{t('admin.payments.status.overdue')}</option>
        </select>
      </div>

      {/* Table */}
      <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
        <table className="w-full text-left">
          <thead className="bg-slate-50 border-b border-slate-200">
            <tr>
              <th className="px-6 py-4 font-semibold text-slate-700 text-sm">{t('admin.payments.table.student')}</th>
              <th className="px-6 py-4 font-semibold text-slate-700 text-sm">{t('admin.payments.table.concept')}</th>
              <th className="px-6 py-4 font-semibold text-slate-700 text-sm">{t('admin.payments.table.amount')}</th>
              <th className="px-6 py-4 font-semibold text-slate-700 text-sm">{t('admin.payments.table.due_date')}</th>
              <th className="px-6 py-4 font-semibold text-slate-700 text-sm">{t('admin.payments.table.status')}</th>
              <th className="px-6 py-4 font-semibold text-slate-700 text-sm">{t('admin.payments.table.actions')}</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100">
            {filteredPayments.map((payment) => {
                const st = getStatus(payment);
                return (
              <tr key={payment.id} className="hover:bg-slate-50 transition-colors">
                <td className="px-6 py-4">
                  <div className="font-medium text-slate-900">{payment.student_name} {payment.student_surname}</div>
                  <div className="text-xs text-slate-500">{payment.course}</div>
                </td>
                <td className="px-6 py-4 text-sm text-slate-600">
                  <div className="flex flex-wrap gap-1">
                    {payment.activities && Array.isArray(payment.activities) && payment.activities.map(act => (
                        <span key={act} className="text-xs bg-slate-100 px-1 rounded">{act}</span>
                    ))}
                  </div>
                </td>
                <td className="px-6 py-4 text-sm font-medium text-slate-900">
                  {Number(payment.amount).toFixed(2)}€
                </td>
                <td className="px-6 py-4 text-sm text-slate-600">
                  {new Date(payment.due_date).toLocaleDateString()}
                </td>
                <td className="px-6 py-4">
                  <span className={`inline-flex items-center px-2 py-1 text-xs font-medium rounded-full ${
                    st === 'paid' ? 'bg-green-50 text-green-700' :
                    st === 'overdue' ? 'bg-red-50 text-red-700' :
                    'bg-amber-50 text-amber-700'
                  }`}>
                    {st === 'paid' ? t('admin.payments.status.paid') : st === 'overdue' ? t('admin.payments.status.overdue') : t('admin.payments.status.pending')}
                  </span>
                </td>
                <td className="px-6 py-4">
                  <div className="flex gap-2">
                    <button 
                        onClick={() => togglePaymentStatus(payment.id, payment.status)}
                        className={`p-1.5 transition-colors rounded ${payment.status === 'paid' ? 'text-amber-500 hover:bg-amber-50' : 'text-green-500 hover:bg-green-50'}`} 
                        title={payment.status === 'paid' ? "Marcar com pendent" : "Marcar com pagat"}
                    >
                      {payment.status === 'paid' ? <XCircle className="w-5 h-5" /> : <CheckCircle className="w-5 h-5" />}
                    </button>
                    <button 
                        onClick={() => handleEdit(payment)}
                        className="p-1.5 text-blue-600 hover:bg-blue-50 rounded transition-colors"
                        title="Editar"
                    >
                        <Edit className="w-5 h-5" />
                    </button>
                    <button 
                        onClick={() => handleDelete(payment.id)}
                        className="p-1.5 text-red-600 hover:bg-red-50 rounded transition-colors"
                        title="Eliminar"
                    >
                        <Trash2 className="w-5 h-5" />
                    </button>
                  </div>
                </td>
              </tr>
            )})}
          </tbody>
        </table>
        {filteredPayments.length === 0 && (
          <div className="p-12 text-center text-slate-500">
            {t('admin.payments.table.no_results')}
          </div>
        )}
      </div>

      <EditPaymentModal 
        isOpen={isModalOpen}
        onClose={() => setIsModalOpen(false)}
        onSave={handleSavePayment}
        payment={editingPayment}
      />
    </div>
  );
}

import { useEffect, useState, useMemo } from 'react';
import { supabase } from '../../../lib/supabase';
import type { ShopProduct } from '../../../features/shop/types/shop';
import { Package, Search, Plus, Download, Calculator, AlertTriangle, Edit, Info } from 'lucide-react';
import { ProductEditorModal } from '../../../components/admin/ProductEditorModal';
import { useContentTranslation } from '../../../hooks/useContentTranslation';
import { motion, AnimatePresence } from 'framer-motion';
import { sortSizes, calculateChandalStock } from '../../../utils/productUtils';
import { ExportService } from '../../../services/ExportService';

export function InventoryPage() {
  const { tContent } = useContentTranslation();
  const [products, setProducts] = useState<ShopProduct[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState('');
  const [savingId, setSavingId] = useState<string | null>(null);
  const [editingProduct, setEditingProduct] = useState<ShopProduct | null>(null);
  const [isModalOpen, setIsModalOpen] = useState(false);

  useEffect(() => {
    fetchInventory();
  }, []);

  async function fetchInventory() {
    try {
      setLoading(true);
      const { data, error } = await supabase
        .from('shop_products')
        .select(`
          *,
          variants:shop_variants(*)
        `)
        .order('name');

      if (error) throw error;
      setProducts(data || []);
    } catch (error) {
      console.error('Error fetching inventory:', error);
    } finally {
      setLoading(false);
    }
  }

  // Càlcul dinàmic de l'estoc del xandall complet
  const processedProducts = useMemo(() => {
    return calculateChandalStock(products);
  }, [products]);

  const handleStockUpdate = async (variantId: string, newStock: string) => {
    const stock = parseInt(newStock);
    if (isNaN(stock)) return;

    setSavingId(variantId);
    try {
      const { error } = await supabase
        .from('shop_variants')
        .update({ stock })
        .eq('id', variantId);

      if (error) throw error;

      setProducts(prev => prev.map(p => ({
        ...p,
        variants: p.variants?.map(v =>
          v.id === variantId ? { ...v, stock } : v
        )
      })));
    } catch (error) {
      console.error('Error updating stock:', error);
      alert('Error updating stock');
    } finally {
      setSavingId(null);
    }
  };

  const handleExportPDF = () => {
    ExportService.exportInventoryPDF(processedProducts);
  };

  const filteredProducts = processedProducts.filter(p =>
    p.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
    tContent(p, 'name').toLowerCase().includes(searchTerm.toLowerCase())
  );

  if (loading) {
    return (
      <div className="flex flex-col justify-center items-center h-64 gap-4">
        <div className="animate-spin rounded-full h-10 w-10 border-b-2 border-primary"></div>
        <p className="text-slate-500 font-medium animate-pulse">Carregant inventari...</p>
      </div>
    )
  }

  return (
    <div className="p-4 md:p-8 max-w-7xl mx-auto space-y-8">
      {/* Header Section */}
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h1 className="text-3xl font-extrabold text-slate-900 dark:text-white flex items-center gap-3">
            <Package className="w-8 h-8 text-primary" />
            Gestió d'Inventari
          </h1>
          <p className="text-slate-500 dark:text-slate-400 mt-1">Controla l'estoc, preus i talles dels productes de la botiga.</p>
        </div>

        <div className="flex flex-wrap items-center gap-3">
          <div className="relative flex-1 min-w-[200px] md:w-64">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 w-4 h-4" />
            <input
              type="text"
              placeholder="Buscar producte..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="w-full pl-10 pr-4 py-2.5 bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-xl text-sm outline-none focus:ring-2 focus:ring-primary/20 focus:border-primary transition-all shadow-sm"
            />
          </div>
          <button
            onClick={handleExportPDF}
            className="flex items-center gap-2 px-4 py-2.5 bg-slate-100 dark:bg-slate-800 text-slate-700 dark:text-slate-300 font-bold rounded-xl hover:bg-slate-200 dark:hover:bg-slate-700 transition-all active:scale-95 border border-slate-200 dark:border-slate-700"
          >
            <Download className="w-5 h-5" />
            <span>Descarregar PDF</span>
          </button>
          <button
            onClick={() => {
              setEditingProduct(null);
              setIsModalOpen(true);
            }}
            className="flex items-center gap-2 px-5 py-2.5 bg-primary text-white font-bold rounded-xl hover:bg-primary-dark transition-all shadow-lg shadow-primary/20 active:scale-95 whitespace-nowrap"
          >
            <Plus className="w-5 h-5" />
            <span>Nou Producte</span>
          </button>
        </div>
      </div>

      {/* Products Grid/List */}
      <div className="space-y-6">
        <AnimatePresence mode="popLayout">
          {filteredProducts.map((product) => {
            const isCalculated = (product as any).isCalculated;
            return (
              <motion.div
                key={product.id}
                layout
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                exit={{ opacity: 0, scale: 0.95 }}
                className="bg-white dark:bg-slate-900 rounded-2xl border border-slate-200 dark:border-slate-800 shadow-sm overflow-hidden hover:shadow-md transition-shadow"
              >
                {/* Product Header inside Card */}
                <div className="p-5 border-b border-slate-100 dark:border-slate-800 bg-slate-50/50 dark:bg-slate-800/30 flex items-center justify-between">
                  <div className="flex items-center gap-4">
                    <div className="w-12 h-12 bg-white dark:bg-slate-800 rounded-xl border border-slate-200 dark:border-slate-700 flex items-center justify-center overflow-hidden">
                      {product.image_url ? (
                        <img src={product.image_url} alt="" className="w-full h-full object-cover" />
                      ) : (
                        <Package className="w-6 h-6 text-slate-300" />
                      )}
                    </div>
                    <div>
                      <h3 className="font-bold text-slate-900 dark:text-white text-lg">{tContent(product, 'name')}</h3>
                      <div className="flex items-center gap-2 mt-0.5">
                        <span className="px-2 py-0.5 bg-blue-50 dark:bg-blue-900/40 text-blue-600 dark:text-blue-400 text-[10px] font-bold uppercase rounded-md tracking-wider">
                          {product.category}
                        </span>
                        {isCalculated && (
                          <span className="flex items-center gap-1 px-2 py-0.5 bg-purple-50 dark:bg-purple-900/40 text-purple-600 dark:text-purple-400 text-[10px] font-bold uppercase rounded-md tracking-wider">
                            <Calculator className="w-3 h-3" /> Estoc Calculat
                          </span>
                        )}
                        {(!product.variants || product.variants.length === 0) && (
                          <span className="flex items-center gap-1 text-amber-500 text-[10px] font-bold">
                            <AlertTriangle className="w-3 h-3" /> Sense talles
                          </span>
                        )}
                      </div>
                    </div>
                  </div>
                  <button
                    onClick={() => {
                      setEditingProduct(product);
                      setIsModalOpen(true);
                    }}
                    className="flex items-center gap-2 px-4 py-2 text-slate-600 dark:text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-xl transition-all font-semibold text-sm"
                  >
                    <Edit className="w-4 h-4" />
                    <span>Editar</span>
                  </button>
                </div>

                {/* Variants Table/List */}
                <div className="overflow-x-auto">
                  <table className="w-full text-sm text-left">
                    <thead className="bg-slate-50/30 dark:bg-slate-800/20 text-slate-400 uppercase text-[10px] font-bold tracking-widest">
                      <tr>
                        <th className="px-6 py-3">Talla / Variant</th>
                        <th className="px-6 py-3">Preu Soci</th>
                        <th className="px-6 py-3">Preu No Soci</th>
                        <th className="px-6 py-3">Estoc Actual</th>
                        <th className="px-6 py-3 text-right">Estat</th>
                      </tr>
                    </thead>
                    <tbody className="divide-y divide-slate-50 dark:divide-slate-800">
                      {sortSizes(product.variants || []).map((variant) => (
                        <tr key={variant.id} className="group hover:bg-slate-50 dark:hover:bg-slate-800/40 transition-colors">
                          <td className="px-6 py-4">
                            <span className="font-mono bg-slate-100 dark:bg-slate-800 px-2 py-1 rounded text-xs font-bold">{variant.size}</span>
                          </td>
                          <td className="px-6 py-4 font-semibold text-slate-600 dark:text-slate-300">
                            {variant.price_member}€
                          </td>
                          <td className="px-6 py-4 font-semibold text-slate-600 dark:text-slate-300">
                            {variant.price_non_member}€
                          </td>
                          <td className="px-6 py-4">
                            <div className="flex items-center gap-2">
                              {isCalculated ? (
                                <div className="w-20 px-3 py-1.5 rounded-lg border bg-slate-100 dark:bg-slate-800 border-slate-200 dark:border-slate-700 text-slate-500 font-bold text-sm flex items-center justify-center cursor-not-allowed" title="L'estoc es calcula automàticament">
                                  {variant.stock}
                                </div>
                              ) : (
                                <>
                                  <input
                                    type="number"
                                    defaultValue={variant.stock}
                                    className={`w-20 px-3 py-1.5 rounded-lg border text-sm focus:ring-2 focus:ring-primary/20 outline-none transition-all ${variant.stock <= 0
                                      ? 'bg-red-50 dark:bg-red-900/20 border-red-200 dark:border-red-800 text-red-600'
                                      : 'bg-white dark:bg-slate-800 border-slate-200 dark:border-slate-700'
                                      }`}
                                    onBlur={(e) => {
                                      if (e.target.value !== variant.stock.toString()) {
                                        handleStockUpdate(variant.id, e.target.value);
                                      }
                                    }}
                                  />
                                  {savingId === variant.id && (
                                    <div className="animate-spin w-3 h-3 border-2 border-primary border-t-transparent rounded-full"></div>
                                  )}
                                </>
                              )}
                            </div>
                          </td>
                          <td className="px-6 py-4 text-right">
                            {variant.stock <= 0 ? (
                              <span className="px-2 py-1 bg-red-100 dark:bg-red-900/30 text-red-600 dark:text-red-400 text-[10px] font-black rounded-full uppercase">Esgotat</span>
                            ) : variant.stock <= 5 ? (
                              <span className="px-2 py-1 bg-amber-100 dark:bg-amber-900/30 text-amber-600 dark:text-amber-400 text-[10px] font-black rounded-full uppercase">Baix estoc</span>
                            ) : (
                              <span className="px-2 py-1 bg-green-100 dark:bg-green-900/30 text-green-600 dark:text-green-400 text-[10px] font-black rounded-full uppercase">En estoc</span>
                            )}
                          </td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                  {(!product.variants || product.variants.length === 0) && (
                    <div className="p-8 text-center bg-slate-50/50 dark:bg-slate-800/10">
                      <p className="text-slate-400 text-sm italic">Aquest producte no té variants configurades.</p>
                    </div>
                  )}
                </div>
              </motion.div>
            );
          })}
        </AnimatePresence>

        {filteredProducts.length === 0 && (
          <div className="text-center py-20 bg-white dark:bg-slate-900 rounded-3xl border border-dashed border-slate-200 dark:border-slate-800 shadow-inner">
            <div className="inline-flex items-center justify-center p-4 bg-slate-50 dark:bg-slate-800 rounded-full mb-4">
              <Search className="w-8 h-8 text-slate-300" />
            </div>
            <h3 className="text-xl font-bold dark:text-white">No s'han trobat productes</h3>
            <p className="text-slate-500 mt-2">Prova amb una altra cerca o crea un producte nou.</p>
          </div>
        )}
      </div>

      {/* Info Legend */}
      <div className="flex flex-col md:flex-row items-center justify-center gap-6 p-6 bg-blue-50/50 dark:bg-blue-900/10 border border-blue-100 dark:border-blue-900/30 rounded-2xl">
        <div className="flex items-center gap-2 text-sm text-blue-700 dark:text-blue-400 text-center">
          <Info className="w-4 h-4 flex-shrink-0" />
          <span>
            L'estoc del <strong>Xandall Complet</strong> es calcula automàticament segons les unitats disponibles de pantalons i sudaderes per a cada talla.
          </span>
        </div>
      </div>

      {isModalOpen && (
        <ProductEditorModal
          isOpen={true}
          onClose={() => {
            setIsModalOpen(false);
            setEditingProduct(null);
          }}
          product={editingProduct}
          onSaved={() => {
            fetchInventory();
            setIsModalOpen(false);
            setEditingProduct(null);
          }}
        />
      )}
    </div>
  );
}

import { useState, useEffect, useMemo } from 'react';
import { ShopService } from '../../../features/shop/services/ShopService';
import { Search, Plus, LayoutDashboard, Archive, Euro, Truck, CheckCircle, XCircle, Settings, Trash2 } from 'lucide-react';
import { format } from 'date-fns';
import { ca } from 'date-fns/locale';
import { OrderEditModal } from '../../../features/shop/components/OrderEditModal';
import { motion, AnimatePresence } from 'framer-motion';

interface Order {
    id: string;
    created_at: string;
    total_amount: number;
    customer_name: string;
    payment_status: 'paid' | 'pending';
    delivery_status: 'pending' | 'delivered' | 'not_picked_up';
    items?: any[];
}

export function OrdersPage() {
    const [orders, setOrders] = useState<Order[]>([]);
    const [loading, setLoading] = useState(true);
    const [selectedOrder, setSelectedOrder] = useState<Order | null>(null);
    const [view, setView] = useState<'active' | 'archived'>('active');
    const [searchTerm, setSearchTerm] = useState('');
    const [isCreating, setIsCreating] = useState(false);
    const [newCustomerName, setNewCustomerName] = useState('');

    const fetchOrders = async () => {
        try {
            const data = await ShopService.getOrders() as any[];
            setOrders(data);
        } catch (error) {
            console.error('Error fetching orders:', error);
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchOrders();
    }, []);

    const handleCreateOrder = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!newCustomerName.trim()) return;

        try {
            const newOrder = await ShopService.createEmptyOrder(newCustomerName);
            setNewCustomerName('');
            setIsCreating(false);
            fetchOrders();
            // Automatically open editor for the new order to add items
            setSelectedOrder({ ...newOrder, items: [] });
        } catch (err) {
            alert("Error creant la comanda");
        }
    };

    const handlePaymentUpdate = async (id: string, status: 'paid' | 'pending') => {
        try {
            await ShopService.updatePaymentStatus(id, status);
            fetchOrders();
        } catch (err) {
            console.error(err);
            alert("Error actualitzant l'estat de pagament");
        }
    };

    const handleDeliveryUpdate = async (id: string, status: Order['delivery_status']) => {
        try {
            await ShopService.updateDeliveryStatus(id, status);
            fetchOrders();
        } catch (err) {
            console.error(err);
            alert("Error actualitzant l'estat d'entrega");
        }
    };

    const handleDeleteOrder = async (id: string) => {
        if (!window.confirm('Estàs segur que vols eliminar aquesta comanda? Aquesta acció no es pot desfer.')) {
            return;
        }

        try {
            await ShopService.deleteOrder(id);
            fetchOrders();
        } catch (err) {
            console.error(err);
            alert("Error eliminant la comanda");
        }
    };

    const filteredOrders = useMemo(() => {
        return orders.filter(order => {
            const matchesSearch = order.customer_name.toLowerCase().includes(searchTerm.toLowerCase()) ||
                order.id.toLowerCase().includes(searchTerm.toLowerCase());

            const isArchived = order.delivery_status === 'delivered' || order.delivery_status === 'not_picked_up';

            if (view === 'active') {
                return matchesSearch && !isArchived;
            } else {
                return matchesSearch && isArchived;
            }
        });
    }, [orders, searchTerm, view]);

    const stats = useMemo(() => {
        const active = orders.filter(o => o.delivery_status === 'pending');
        const revenue = orders.filter(o => o.payment_status === 'paid').reduce((acc, o) => acc + o.total_amount, 0);
        return {
            pendingCount: active.length,
            totalRevenue: revenue
        };
    }, [orders]);

    if (loading) {
        return (
            <div className="flex flex-col justify-center items-center h-64 gap-4">
                <div className="animate-spin rounded-full h-10 w-10 border-b-2 border-primary"></div>
                <p className="text-slate-500 font-medium animate-pulse">Carregant comandes...</p>
            </div>
        );
    }

    return (
        <div className="p-4 md:p-8 max-w-7xl mx-auto space-y-8">
            {/* Header Area */}
            <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
                <div>
                    <h1 className="text-3xl font-extrabold text-slate-900 dark:text-white flex items-center gap-3">
                        <LayoutDashboard className="w-8 h-8 text-primary" />
                        Comandes i Reserves
                    </h1>
                    <p className="text-slate-500 dark:text-slate-400 mt-1">
                        Gestió de reserves, vendes presencials i seguiment d'entregues.
                    </p>
                </div>

                <div className="flex flex-wrap items-center gap-3">
                    <div className="flex bg-slate-100 dark:bg-slate-800 p-1 rounded-xl">
                        <button
                            onClick={() => setView('active')}
                            className={`px-4 py-2 rounded-lg text-sm font-bold transition-all ${view === 'active' ? 'bg-white dark:bg-slate-700 text-primary shadow-sm' : 'text-slate-500'} `}
                        >
                            Actives ({orders.filter(o => o.delivery_status === 'pending').length})
                        </button>
                        <button
                            onClick={() => setView('archived')}
                            className={`px-4 py-2 rounded-lg text-sm font-bold transition-all ${view === 'archived' ? 'bg-white dark:bg-slate-700 text-primary shadow-sm' : 'text-slate-500'} `}
                        >
                            Arxiu ({orders.filter(o => o.delivery_status !== 'pending').length})
                        </button>
                    </div>

                    <button
                        onClick={() => setIsCreating(true)}
                        className="flex items-center gap-2 px-5 py-2.5 bg-primary text-white font-bold rounded-xl hover:bg-primary-dark transition-all shadow-lg shadow-primary/20 active:scale-95 whitespace-nowrap"
                    >
                        <Plus className="w-5 h-5" />
                        <span>Nova Venda</span>
                    </button>
                </div>
            </div>

            {/* Quick Stats & Search */}
            <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
                <div className="md:col-span-2 relative">
                    <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 w-5 h-5" />
                    <input
                        type="text"
                        placeholder="Buscar per nom de client o ID..."
                        value={searchTerm}
                        onChange={(e) => setSearchTerm(e.target.value)}
                        className="w-full pl-12 pr-4 py-3 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-2xl outline-none focus:ring-2 focus:ring-primary/20 focus:border-primary transition-all shadow-sm"
                    />
                </div>
                <div className="bg-blue-50 dark:bg-blue-900/20 p-4 rounded-2xl border border-blue-100 dark:border-blue-900/30 flex flex-col justify-center">
                    <span className="text-[10px] font-black uppercase tracking-widest text-blue-500 mb-1">Pendents Entrega</span>
                    <span className="text-2xl font-black text-blue-700 dark:text-blue-400">{stats.pendingCount}</span>
                </div>
                <div className="bg-green-50 dark:bg-green-900/20 p-4 rounded-2xl border border-green-100 dark:border-green-900/30 flex flex-col justify-center">
                    <span className="text-[10px] font-black uppercase tracking-widest text-green-500 mb-1">Facturació Total</span>
                    <span className="text-2xl font-black text-green-700 dark:text-green-400">{stats.totalRevenue.toFixed(2)}€</span>
                </div>
            </div>

            {/* Manual Order Creation Form */}
            <AnimatePresence>
                {isCreating && (
                    <motion.form
                        initial={{ opacity: 0, height: 0 }}
                        animate={{ opacity: 1, height: 'auto' }}
                        exit={{ opacity: 0, height: 0 }}
                        onSubmit={handleCreateOrder}
                        className="overflow-hidden"
                    >
                        <div className="bg-primary/5 border-2 border-dashed border-primary/30 rounded-3xl p-6 flex flex-col md:flex-row items-center gap-4">
                            <div className="flex-1 w-full">
                                <label className="block text-xs font-black uppercase tracking-widest text-primary mb-2">Venda Presencial - Nom del Client</label>
                                <input
                                    autoFocus
                                    type="text"
                                    placeholder="Introdueix nom i cognoms..."
                                    value={newCustomerName}
                                    onChange={(e) => setNewCustomerName(e.target.value)}
                                    className="w-full px-4 py-3 rounded-xl border-none ring-1 ring-primary/20 focus:ring-2 focus:ring-primary outline-none text-lg font-bold"
                                />
                            </div>
                            <div className="flex gap-2 shrink-0">
                                <button
                                    type="button"
                                    onClick={() => setIsCreating(false)}
                                    className="px-6 py-3 text-slate-500 font-bold hover:bg-slate-100 rounded-xl transition-all"
                                >
                                    Cancel·lar
                                </button>
                                <button
                                    type="submit"
                                    className="px-8 py-3 bg-primary text-white font-bold rounded-xl shadow-lg shadow-primary/20 hover:bg-primary-dark transition-all"
                                >
                                    Crear Comanda
                                </button>
                            </div>
                        </div>
                    </motion.form>
                )}
            </AnimatePresence>

            {/* Orders List */}
            <div className="space-y-4">
                <AnimatePresence mode="popLayout">
                    {filteredOrders.map((order: any) => (
                        <motion.div
                            key={order.id}
                            layout
                            initial={{ opacity: 0, scale: 0.98 }}
